HttpClient Ota::SetupHttp()
{
    // Create HTTP client instance
    HttpClient httpClient;

    // Set device identification header
    httpClient.setHeader("X-Device-ID", GetDeviceId());

    // Set user agent header
    httpClient.setHeader("User-Agent", "OTA-Client/1.0");

    // Set language header
    httpClient.setHeader("Accept-Language", "en-US,en;q=0.9");

    // Set content type header for firmware updates
    httpClient.setHeader("Content-Type", "application/octet-stream");

    // Check device provisioning status and set serial number if provisioned
    if (IsDeviceProvisioned()) {
        httpClient.setHeader("X-Device-Serial", GetDeviceSerialNumber());
    }

    // Set additional OTA-specific headers
    httpClient.setHeader("Connection", "keep-alive");
    httpClient.setHeader("Cache-Control", "no-cache");

    // Configure timeout settings appropriate for firmware downloads
    httpClient.setTimeout(30000); // 30 second timeout

    // Return the configured HTTP client
    return httpClient;
}

int Ota::CheckVersion() {
    // Initialize return code
    int result = OTA_ERROR_NONE;

    // Prepare HTTP client for server communication
    HttpClient httpClient;
    HttpResponse response;

    // Build request URL with current version info
    std::string url = SERVER_URL + "/api/firmware/check";
    std::string requestBody = "{\"current_version\":\"" + GetCurrentVersion() + 
                             "\",\"device_id\":\"" + GetDeviceId() + "\"}";

    // Send HTTP POST request to check for updates
    if (!httpClient.Post(url, requestBody, "application/json", response)) {
        return OTA_ERROR_NETWORK;
    }

    // Check HTTP response status
    if (response.GetStatusCode() != 200) {
        return OTA_ERROR_SERVER;
    }

    // Parse JSON response
    JsonParser parser;
    JsonObject jsonResponse;

    if (!parser.Parse(response.GetBody(), jsonResponse)) {
        return OTA_ERROR_JSON_PARSE;
    }

    // Check if update is available
    bool updateAvailable = false;
    if (!jsonResponse.GetBool("update_available", updateAvailable)) {
        return OTA_ERROR_JSON_PARSE;
    }

    if (!updateAvailable) {
        return OTA_ERROR_NONE; // No update available
    }

    // Extract new version information
    std::string newVersion;
    if (!jsonResponse.GetString("new_version", newVersion)) {
        return OTA_ERROR_JSON_PARSE;
    }

    // Compare versions
    if (!IsNewerVersion(newVersion, GetCurrentVersion())) {
        return OTA_ERROR_NONE; // Current version is already up to date
    }

    // Store update information for later use
    m_pendingUpdate.version = newVersion;

    // Extract firmware download URL
    std::string firmwareUrl;
    if (jsonResponse.GetString("firmware_url", firmwareUrl)) {
        m_pendingUpdate.downloadUrl = firmwareUrl;
    } else {
        return OTA_ERROR_JSON_PARSE;
    }

    // Handle activation-related data if present
    JsonObject activationData;
    if (jsonResponse.GetObject("activation", activationData)) {
        result = ProcessActivationData(activationData);
        if (result != OTA_ERROR_NONE) {
            return result;
        }
    }

    // Handle MQTT configuration updates if present
    JsonObject mqttConfig;
    if (jsonResponse.GetObject("mqtt_config", mqttConfig)) {
        result = UpdateMqttConfiguration(mqttConfig);
        if (result != OTA_ERROR_NONE) {
            return result;
        }
    }

    // Extract additional update metadata
    int fileSize = 0;
    if (jsonResponse.GetInt("file_size", fileSize)) {
        m_pendingUpdate.fileSize = fileSize;
    }

    std::string checksum;
    if (jsonResponse.GetString("checksum", checksum)) {
        m_pendingUpdate.checksum = checksum;
    }

    // Mark that an update is available
    m_updateAvailable = true;

    return OTA_ERROR_UPDATE_AVAILABLE;
}

void Ota::MarkCurrentVersionValid() {
    // Log the start of the validation process
    LOG_DEBUG("Starting validation of current firmware version");

    // Get information about the currently running partition
    PartitionInfo currentPartition;
    if (!GetCurrentRunningPartition(currentPartition)) {
        LOG_ERROR("Failed to get current running partition information");
        return;
    }

    // Skip validation for factory partition
    if (currentPartition.type == PARTITION_TYPE_FACTORY) {
        LOG_INFO("Skipping validation for factory partition");
        return;
    }

    // Check if the partition is in pending verification state
    if (currentPartition.state != PARTITION_STATE_PENDING_VERIFICATION) {
        LOG_DEBUG("Partition is not in pending verification state, current state: %d", 
                  currentPartition.state);
        return;
    }

    // Mark the current partition as valid
    if (!SetPartitionState(currentPartition.partitionId, PARTITION_STATE_VALID)) {
        LOG_ERROR("Failed to mark partition %d as valid", currentPartition.partitionId);
        return;
    }

    // Log successful validation
    LOG_INFO("Successfully validated firmware partition %d", currentPartition.partitionId);

    // Optional: Update boot configuration to ensure device boots from this partition
    if (!UpdateBootConfiguration(currentPartition.partitionId)) {
        LOG_WARN("Failed to update boot configuration, but partition is marked valid");
    }
}

bool Ota::Upgrade(const std::string& firmwareUrl, std::function<void(int progress, size_t speed)> progressCallback) {
    // Validate input parameters
    if (firmwareUrl.empty() || !progressCallback) {
        return false;
    }

    try {
        // Initialize variables for download tracking
        size_t totalBytes = 0;
        size_t downloadedBytes = 0;
        size_t lastReportedBytes = 0;
        auto startTime = std::chrono::steady_clock::now();
        auto lastProgressTime = startTime;

        // Step 1: Start firmware download
        HttpClient httpClient;
        HttpRequest request(firmwareUrl);
        HttpResponse response;

        // Set up progress tracking in HTTP client
        httpClient.setOnProgressCallback([&](size_t bytesReceived, size_t totalSize) {
            downloadedBytes = bytesReceived;
            totalBytes = totalSize > 0 ? totalSize : totalBytes;

            // Calculate progress percentage
            int progress = (totalBytes > 0) ? static_cast<int>((downloadedBytes * 100) / totalBytes) : 0;

            // Calculate download speed (bytes per second)
            auto currentTime = std::chrono::steady_clock::now();
            auto timeElapsed = std::chrono::duration_cast<std::chrono::milliseconds>(currentTime - lastProgressTime).count();
            size_t speed = 0;

            if (timeElapsed > 0) {
                size_t bytesSinceLastReport = downloadedBytes - lastReportedBytes;
                speed = (bytesSinceLastReport * 1000) / timeElapsed; // bytes per second
            }

            // Call progress callback
            if (progressCallback) {
                progressCallback(progress, speed);
            }

            lastProgressTime = currentTime;
            lastReportedBytes = downloadedBytes;
        });

        // Execute HTTP GET request
        if (!httpClient.get(request, response)) {
            return false;
        }

        // Check HTTP response status
        if (response.getStatusCode() != 200) {
            return false;
        }

        // Get firmware data
        const std::vector<uint8_t>& firmwareData = response.getBody();
        if (firmwareData.empty()) {
            return false;
        }

        // Step 2: Verify firmware header integrity
        if (!verifyFirmwareHeader(firmwareData)) {
            return false;
        }

        // Step 3: Check version compatibility
        if (!isVersionCompatible(firmwareData)) {
            return false;
        }

        // Step 4: Validate firmware integrity (checksum/CRC)
        if (!validateFirmwareIntegrity(firmwareData)) {
            return false;
        }

        // Step 5: Prepare OTA partition for write
        if (!prepareOtaPartition()) {
            return false;
        }

        // Step 6: Write firmware to OTA partition
        size_t chunkSize = 4096; // Write in 4KB chunks
        size_t offset = 0;

        while (offset < firmwareData.size()) {
            size_t remainingBytes = firmwareData.size() - offset;
            size_t currentChunkSize = std::min(chunkSize, remainingBytes);

            if (!writeToOtaPartition(firmwareData.data() + offset, currentChunkSize, offset)) {
                // Cleanup on failure
                cleanupOtaPartition();
                return false;
            }

            offset += currentChunkSize;

            // Report progress during write phase (if needed)
            int writeProgress = 100 + static_cast<int>((offset * 100) / firmwareData.size());
            writeProgress = std::min(writeProgress, 150); // Cap at 150% to distinguish from download phase

            if (progressCallback) {
                progressCallback(writeProgress, 0); // Speed not applicable during write
            }
        }

        // Step 7: Finalize OTA partition (set boot flag, etc.)
        if (!finalizeOtaPartition()) {
            cleanupOtaPartition();
            return false;
        }

        // Step 8: Mark OTA as ready for next boot
        if (!markOtaReady()) {
            return false;
        }

        // Report final progress
        if (progressCallback) {
            progressCallback(100, 0);
        }

        return true;

    } catch (const std::exception& e) {
        // Log error if logging is available
        // Logger::error("OTA Upgrade failed: " + std::string(e.what()));
        return false;
    } catch (...) {
        // Handle any other unexpected exceptions
        return false;
    }
}

// Helper method implementations (these would typically be private methods in the class)

bool Ota::verifyFirmwareHeader(const std::vector<uint8_t>& firmwareData) {
    // Check minimum firmware size for header
    if (firmwareData.size() < sizeof(FirmwareHeader)) {
        return false;
    }

    // Cast header portion
    const FirmwareHeader* header = reinterpret_cast<const FirmwareHeader*>(firmwareData.data());

    // Verify magic number
    if (header->magic != FIRMWARE_MAGIC_NUMBER) {
        return false;
    }

    // Verify header checksum
    uint32_t calculatedChecksum = calculateHeaderChecksum(header);
    if (calculatedChecksum != header->headerChecksum) {
        return false;
    }

    return true;
}

bool Ota::isVersionCompatible(const std::vector<uint8_t>& firmwareData) {
    const FirmwareHeader* header = reinterpret_cast<const FirmwareHeader*>(firmwareData.data());

    // Check if firmware version is newer than current version
    // This is a simplified version check - real implementation would be more complex
    if (header->versionMajor < mCurrentVersion.major ||
        (header->versionMajor == mCurrentVersion.major && header->versionMinor <= mCurrentVersion.minor)) {
        return false; // Downgrade or same version not allowed
    }

    // Check hardware compatibility
    if (header->hardwareId != mHardwareId) {
        return false;
    }

    return true;
}

bool Ota::validateFirmwareIntegrity(const std::vector<uint8_t>& firmwareData) {
    if (firmwareData.size() < sizeof(FirmwareHeader)) {
        return false;
    }

    const FirmwareHeader* header = reinterpret_cast<const FirmwareHeader*>(firmwareData.data());

    // Calculate CRC32 of firmware payload
    size_t payloadOffset = header->headerSize;
    if (payloadOffset >= firmwareData.size()) {
        return false;
    }

    size_t payloadSize = firmwareData.size() - payloadOffset;
    uint32_t calculatedCrc = calculateCRC32(firmwareData.data() + payloadOffset, payloadSize);

    return (calculatedCrc == header->payloadCrc);
}

bool Ota::prepareOtaPartition() {
    // Erase OTA partition
    return flashEraseSector(mOtaPartitionAddress, mOtaPartitionSize);
}

bool Ota::writeToOtaPartition(const uint8_t* data, size_t size, size_t offset) {
    return flashWrite(mOtaPartitionAddress + offset, data, size);
}

bool Ota::finalizeOtaPartition() {
    // Set valid flag or metadata in OTA partition
    OtaMetadata metadata;
    metadata.isValid = true;
    metadata.timestamp = getCurrentTimestamp();
    metadata.crc = calculatePartitionCRC();

    return flashWrite(mOtaMetadataAddress, reinterpret_cast<uint8_t*>(&metadata), sizeof(metadata));
}

bool Ota::markOtaReady() {
    // Set boot configuration to use OTA partition on next boot
    return setBootPartition(mOtaPartitionAddress);
}

void Ota::cleanupOtaPartition() {
    // Invalidate OTA partition on failure
    OtaMetadata metadata = {};
    flashWrite(mOtaMetadataAddress, reinterpret_cast<uint8_t*>(&metadata), sizeof(metadata));
}

// Utility functions (would be implemented based on platform)
uint32_t Ota::calculateHeaderChecksum(const FirmwareHeader* header) {
    // Simple checksum calculation (example implementation)
    uint32_t checksum = 0;
    const uint8_t* data = reinterpret_cast<const uint8_t*>(header);
    for (size_t i = 0; i < sizeof(FirmwareHeader) - sizeof(uint32_t); i++) {
        checksum += data[i];
    }
    return checksum;
}

uint32_t Ota::calculateCRC32(const uint8_t* data, size_t length) {
    // Standard CRC32 implementation
    static uint32_t crcTable[256];
    static bool tableInitialized = false;

    if (!tableInitialized) {
        for (uint32_t i = 0; i < 256; i++) {
            uint32_t crc = i;
            for (int j = 0; j < 8; j++) {
                crc = (crc >> 1) ^ ((crc & 1) ? 0xEDB88320 : 0);
            }
            crcTable[i] = crc;
        }
        tableInitialized = true;
    }

    uint32_t crc = 0xFFFFFFFF;
    for (size_t i = 0; i < length; i++) {
        crc = (crc >> 8) ^ crcTable[(crc & 0xFF) ^ data[i]];
    }

    return crc ^ 0xFFFFFFFF;
}

