namespace Ota {
    std::vector<int> ParseVersion(const std::string& versionString) {
        std::vector<int> versionComponents;

        if (versionString.empty()) {
            return versionComponents;
        }

        std::stringstream ss(versionString);
        std::string component;

        while (std::getline(ss, component, '.')) {
            try {
                int versionNumber = std::stoi(component);
                versionComponents.push_back(versionNumber);
            } catch (const std::exception&) {
                // If conversion fails, we could either skip invalid components
                // or return empty vector. Following robust approach of skipping.
                continue;
            }
        }

        return versionComponents;
    }
}

bool Ota::IsNewVersionAvailable(const std::string& currentVersion, const std::string& candidateVersion) {
    // Helper lambda to parse version string into vector of integers
    auto parseVersion = [](const std::string& versionStr) -> std::vector<int> {
        std::vector<int> versionComponents;
        std::string component;
        std::istringstream iss(versionStr);

        while (std::getline(iss, component, '.')) {
            try {
                versionComponents.push_back(std::stoi(component));
            } catch (const std::exception&) {
                // If conversion fails, treat as 0
                versionComponents.push_back(0);
            }
        }

        return versionComponents;
    };

    // Parse both version strings
    std::vector<int> currentComponents = parseVersion(currentVersion);
    std::vector<int> candidateComponents = parseVersion(candidateVersion);

    // Get the maximum length to compare all components
    size_t maxLen = std::max(currentComponents.size(), candidateComponents.size());

    // Pad shorter vectors with zeros
    currentComponents.resize(maxLen, 0);
    candidateComponents.resize(maxLen, 0);

    // Compare version components segment by segment
    for (size_t i = 0; i < maxLen; ++i) {
        if (candidateComponents[i] > currentComponents[i]) {
            return true;  // Candidate version is newer
        } else if (candidateComponents[i] < currentComponents[i]) {
            return false; // Candidate version is older
        }
        // If equal, continue to next component
    }

    // All components are equal - no new version available
    return false;
}

std::string Ota::GetActivationPayload() {
    // Get the device serial number
    std::string serialNumber = GetDeviceSerialNumber();

    // Check if serial number is available
    if (serialNumber.empty()) {
        // Return empty JSON object if serial number is not available
        return "{}";
    }

    // Get the challenge string
    std::string challenge = GetChallengeString();

    // Create data to be signed (serial + challenge)
    std::string dataToSign = serialNumber + challenge;

    // Compute HMAC-SHA256 signature using hardware-backed key
    std::string signature = ComputeHMACSHA256(dataToSign);

    // Create JSON payload
    std::string jsonPayload = "{";
    jsonPayload += "\"serial\":\"" + serialNumber + "\",";
    jsonPayload += "\"challenge\":\"" + challenge + "\",";
    jsonPayload += "\"signature\":\"" + signature + "\"";
    jsonPayload += "}";

    return jsonPayload;
}

int Ota::Activate()
{
    // Construct the activation URL
    std::string activationUrl = m_baseUrl + "/api/v1/activate";

    // Prepare the activation payload
    std::string payload = "{"
                         "\"device_id\":\"" + m_deviceId + "\","
                         "\"firmware_version\":\"" + m_firmwareVersion + "\","
                         "\"activation_token\":\"" + m_activationToken + "\""
                         "}";

    // Set HTTP headers
    HttpHeaders headers;
    headers["Content-Type"] = "application/json";
    headers["Accept"] = "application/json";

    // Send HTTP POST request
    HttpResponse response;
    HttpResult result = HttpClient::Post(activationUrl, payload, headers, response);

    // Check if HTTP request was successful
    if (result != HTTP_SUCCESS) {
        LogError("Failed to send activation request: %d", result);
        return OTA_ERROR_NETWORK;
    }

    // Handle server response based on HTTP status code
    switch (response.statusCode) {
        case 200: // OK - Activation successful
            {
                // Parse response to verify activation
                JsonParser parser;
                JsonObject jsonResp;
                if (parser.Parse(response.body, jsonResp) == PARSE_SUCCESS) {
                    std::string status;
                    if (jsonResp.GetString("status", status) == PARSE_SUCCESS) {
                        if (status == "activated") {
                            LogInfo("OTA activation successful");
                            m_isActivated = true;
                            return OTA_SUCCESS;
                        } else {
                            LogError("Activation failed: %s", status.c_str());
                            return OTA_ERROR_ACTIVATION_FAILED;
                        }
                    }
                }
                LogWarning("Could not parse activation response, but HTTP 200 received");
                m_isActivated = true;
                return OTA_SUCCESS;
            }
            break;

        case 400: // Bad Request
            LogError("Bad request: %s", response.body.c_str());
            return OTA_ERROR_BAD_REQUEST;

        case 401: // Unauthorized
            LogError("Unauthorized access to activation endpoint");
            return OTA_ERROR_UNAUTHORIZED;

        case 404: // Not Found
            LogError("Activation endpoint not found");
            return OTA_ERROR_ENDPOINT_NOT_FOUND;

        case 409: // Conflict - already activated or invalid state
            LogError("Conflict: %s", response.body.c_str());
            return OTA_ERROR_CONFLICT;

        case 500: // Internal Server Error
            LogError("Server internal error during activation");
            return OTA_ERROR_SERVER_ERROR;

        default:
            LogError("Unexpected HTTP status code: %d", response.statusCode);
            return OTA_ERROR_UNKNOWN;
    }
}

Settings::~Settings() {
    // Check if we have a valid NVS handle and the instance was opened in read-write mode
    if (nvs_handle_ != nullptr && mode_ == READ_WRITE_MODE) {
        // Check if there are unsaved modifications
        if (has_unsaved_changes_) {
            // Commit any pending changes to NVS
            esp_err_t err = nvs_commit(nvs_handle_);
            if (err != ESP_OK) {
                // Log error but continue with cleanup
                // In embedded systems, we might want to handle this differently
                // depending on the logging mechanism available
            }
        }
    }

    // Always close the NVS handle to release resources
    if (nvs_handle_ != nullptr) {
        nvs_close(nvs_handle_);
        nvs_handle_ = nullptr;
    }

    // Reset other member variables to safe defaults
    has_unsaved_changes_ = false;
    mode_ = READ_ONLY_MODE;
}

std::string GetString(const std::string& key, const std::string& defaultValue) {
    nvs_handle_t handle;
    esp_err_t err;

    // Open NVS namespace
    err = nvs_open("storage", NVS_READONLY, &handle);
    if (err != ESP_OK) {
        return defaultValue;
    }

    // Get required buffer length (first call with NULL buffer)
    size_t required_size;
    err = nvs_get_str(handle, key.c_str(), NULL, &required_size);
    if (err != ESP_OK || required_size == 0) {
        nvs_close(handle);
        return defaultValue;
    }

    // Allocate buffer and read the string
    char* buffer = new char[required_size];
    err = nvs_get_str(handle, key.c_str(), buffer, &required_size);

    // Close NVS handle
    nvs_close(handle);

    if (err != ESP_OK) {
        delete[] buffer;
        return defaultValue;
    }

    // Convert to std::string (this automatically handles null termination)
    std::string result(buffer);

    // Clean up allocated memory
    delete[] buffer;

    // Remove trailing null characters if any
    while (!result.empty() && result.back() == '\0') {
        result.pop_back();
    }

    return result;
}

void SetString(const std::string& key, const std::string& value) {
    // Check if the namespace is open for writing
    if (!m_isWritable) {
        // Log warning if namespace is read-only
        LogWarning("Attempt to write to read-only namespace. Key: " + key);
        return;
    }

    // Store the key-value pair in non-volatile storage
    // This would typically involve calling the underlying NVS API
    esp_err_t err = nvs_set_str(m_nvsHandle, key.c_str(), value.c_str());

    if (err != ESP_OK) {
        LogError("Failed to set string in NVS. Key: " + key + ", Error: " + std::to_string(err));
        return;
    }

    // Mark settings as dirty to indicate unsaved changes
    m_isDirty = true;
}

int32_t GetInt(const std::string& key, int32_t defaultValue) {
