    if (!IsNamespaceWritable()) {
        // Log warning if namespace is read-only
        LogWarning("Attempt to write to read-only namespace ignored");
        return;
    }

    // Store the integer value in non-volatile storage under the specified key
    bool writeSuccess = WriteToNVS(key, value);

    // If write operation is successful, mark settings as dirty
