bool Settings::GetBool(const std::string& key, bool defaultValue) {
    nvs_handle_t nvsHandle;
    esp_err_t err;

    // Open NVS handle for reading
    err = nvs_open("settings", NVS_READONLY, &nvsHandle);
    if (err != ESP_OK) {
        return defaultValue;
    }

    // Read boolean value from NVS
    uint8_t value = 0;
    err = nvs_get_u8(nvsHandle, key.c_str(), &value);

    // Close NVS handle
    nvs_close(nvsHandle);

    // Check if read was successful
    if (err != ESP_OK) {
        return defaultValue;
    }

    // Convert uint8_t to bool (0 = false, non-zero = true)
    return (value != 0);
}

void SetBool(const std::string& key, bool value) {
    // Check if namespace is open for writing
    if (IsNamespaceWritable()) {
        // Convert boolean to uint8_t (1 for true, 0 for false)
        uint8_t boolValue = value ? 1 : 0;

        // Store the value in non-volatile storage
        if (StoreValueInNVS(key, boolValue)) {
            // Mark settings as dirty to indicate changes need to be persisted
            MarkSettingsAsDirty();
        } else {
            // Log error if storage operation fails
            LogWarning("Failed to store boolean value for key: " + key);
        }
    } else {
        // Log warning if namespace is not writable
        LogWarning("Namespace is not open for writing. Cannot set boolean value for key: " + key);
    }
}

void EraseKey(const std::string& key) {
    // Check if the namespace is open for writing
    if (!IsNamespaceOpenForWriting()) {
        // Log warning if namespace is read-only
        LogWarning("Cannot erase key '" + key + "': Namespace is read-only");
        return;
    }

    // Validate input key
    if (key.empty()) {
        LogWarning("Cannot erase key: Empty key provided");
        return;
    }

    // Attempt to erase the key from NVS
    esp_err_t err = nvs_erase_key(nvs_handle, key.c_str());

    // Handle the result
    switch (err) {
        case ESP_OK:
            // Key successfully erased
            LogDebug("Key '" + key + "' successfully erased from NVS");
            break;

        case ESP_ERR_NVS_NOT_FOUND:
            // Key doesn't exist - handle gracefully as required
            LogInfo("Key '" + key + "' not found in NVS - nothing to erase");
            break;

        case ESP_ERR_INVALID_ARG:
            // Invalid key name
            LogError("Failed to erase key '" + key + "': Invalid key name");
            break;

        case ESP_ERR_NVS_NOT_INITIALIZED:
            // NVS not initialized
            LogError("Failed to erase key '" + key + "': NVS not initialized");
            break;

        case ESP_ERR_NVS_INVALID_HANDLE:
            // Invalid NVS handle
            LogError("Failed to erase key '" + key + "': Invalid NVS handle");
            break;

        default:
            // Other NVS errors
            LogError("Failed to erase key '" + key + "': NVS error code " + std::to_string(err));
            break;
    }
}

void Settings::EraseAll()
{
    // Check if the NVS namespace is open for writing
    if (m_accessMode == ACCESS_MODE_READ_WRITE)
    {
        // Clear all stored settings in the NVS namespace
        esp_err_t err = nvs_erase_all(m_nvsHandle);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to erase all settings: %s", esp_err_to_name(err));
            return;
        }

        // Commit the changes to persistent storage
        err = nvs_commit(m_nvsHandle);
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to commit erased settings: %s", esp_err_to_name(err));
            return;
        }

        ESP_LOGI(TAG, "All settings have been successfully erased");
    }
    else
    {
        // Log warning if namespace is read-only
        ESP_LOGW(TAG, "Cannot erase settings: NVS namespace is read-only");
    }
}

