    char macStr[18]; // 17 characters + null terminator

    // Read MAC address of WiFi station interface
    esp_err_t err = esp_read_mac(mac, ESP_MAC_WIFI_STA);

    if (err != ESP_OK) {
        // Fallback to wifi API if esp_read_mac fails
        wifi_init_config_t cfg = WIFI_INIT_CONFIG_DEFAULT();
        esp_wifi_init(&cfg);
        err = esp_wifi_get_mac(WIFI_IF_STA, mac);

        if (err != ESP_OK) {
