void PrintTaskCpuUsage(TickType_t xDelayTime)
{
    // Buffer to store task runtime statistics (before and after)
    char pcWriteBuffer[2048];
    char pcWriteBufferAfter[2048];

    // Variables to track task count and detect changes
    UBaseType_t uxTaskCountBefore, uxTaskCountAfter;

    // Get initial task list and runtime statistics
    memset(pcWriteBuffer, 0, sizeof(pcWriteBuffer));
    vTaskList(pcWriteBuffer);

    // Count initial tasks by parsing the buffer
    uxTaskCountBefore = 0;
    char* ptr = pcWriteBuffer;
    while(*ptr != '\0') {
        if(*ptr == '\n') uxTaskCountBefore++;
        ptr++;
    }
    if(strlen(pcWriteBuffer) > 0 && pcWriteBuffer[strlen(pcWriteBuffer)-1] != '\n') {
        uxTaskCountBefore++; // Account for last line without newline
    }

    // Wait for the specified time interval
    vTaskDelay(xDelayTime);

    // Get task list and runtime statistics after delay
    memset(pcWriteBufferAfter, 0, sizeof(pcWriteBufferAfter));
    vTaskList(pcWriteBufferAfter);

    // Count final tasks
    uxTaskCountAfter = 0;
    ptr = pcWriteBufferAfter;
    while(*ptr != '\0') {
        if(*ptr == '\n') uxTaskCountAfter++;
        ptr++;
    }
    if(strlen(pcWriteBufferAfter) > 0 && pcWriteBufferAfter[strlen(pcWriteBufferAfter)-1] != '\n') {
        uxTaskCountAfter++; // Account for last line without newline
    }

    // Print header
    printf("\n=== Task CPU Usage Report ===\n");
    printf("Measurement Duration: %lu ticks\n", (unsigned long)xDelayTime);

    // Check for task creation/deletion
    if(uxTaskCountAfter > uxTaskCountBefore) {
        printf("WARNING: %lu task(s) created during measurement\n", 
               (unsigned long)(uxTaskCountAfter - uxTaskCountBefore));
    } else if(uxTaskCountAfter < uxTaskCountBefore) {
        printf("WARNING: %lu task(s) deleted during measurement\n", 
               (unsigned long)(uxTaskCountBefore - uxTaskCountAfter));
    }

    // Parse and calculate CPU usage for each task
    // Note: This simplified version assumes vTaskGetRunTimeStats is available
    // In a real implementation, you would parse the task lists and calculate differences

    char runtimeStatsBuffer[2048];
    memset(runtimeStatsBuffer, 0, sizeof(runtimeStatsBuffer));

