bool AudioCodec::InputData(std::vector<int16_t>& buffer) {
    // Check if the audio input is properly initialized
    if (!inputStreamInitialized) {
        return false;
    }

    // Determine the number of samples to read
    // If buffer is empty, resize it to a reasonable chunk size
    size_t samplesToRead = buffer.size();
    if (samplesToRead == 0) {
        samplesToRead = DEFAULT_AUDIO_BUFFER_SIZE; // e.g., 1024 samples
        buffer.resize(samplesToRead);
    }

    // Attempt to read audio samples from the input stream
    size_t samplesRead = 0;
    bool readSuccess = false;

    // Platform-specific audio input reading (example implementation)
    #ifdef __linux__
        // Linux ALSA or similar implementation
        samplesRead = ReadFromALSA(buffer.data(), samplesToRead);
        readSuccess = (samplesRead > 0);
    #elif defined(_WIN32)
        // Windows WASAPI or DirectSound implementation
        samplesRead = ReadFromWASAPI(buffer.data(), samplesToRead);
        readSuccess = (samplesRead > 0);
    #elif defined(__APPLE__)
        // macOS CoreAudio implementation
        samplesRead = ReadFromCoreAudio(buffer.data(), samplesToRead);
        readSuccess = (samplesRead > 0);
    #else
        // Generic implementation or simulation
        readSuccess = ReadFromGenericInput(buffer.data(), samplesToRead, &samplesRead);
    #endif

    // Resize buffer to actual number of samples read
    if (samplesRead < samplesToRead) {
        buffer.resize(samplesRead);
    }

    // Return true if we successfully read some samples
    return readSuccess && (samplesRead > 0);
}

bool AudioCodec::Start()
{
    // Initialize the codec hardware
    if (!InitializeHardware())
    {
        return false;
    }

    // Configure I2S transmit handle for playback
    if (!ConfigureI2STransmit())
    {
        return false;
    }

    // Configure I2S receive handle for recording
    if (!ConfigureI2SReceive())
    {
        return false;
    }

    // Apply output volume settings (use saved settings or defaults)
    uint16_t outputVolume = GetSavedOutputVolume();
    if (!SetOutputVolume(outputVolume))
    {
        return false;
    }

    // Apply input volume settings (use saved settings or defaults)
    uint16_t inputVolume = GetSavedInputVolume();
    if (!SetInputVolume(inputVolume))
    {
        return false;
    }

    // Enable audio output path
    if (!EnableOutputPath())
    {
        return false;
    }

    // Enable audio input path
    if (!EnableInputPath())
    {
        return false;
    }

    // Start I2S communication
    if (!StartI2SCommunication())
    {
        return false;
    }

    // Mark codec as started
    m_isStarted = true;

    return true;
}

