Es8388AudioCodec::Es8388AudioCodec(
    void *i2s_config,
    i2c_port_t i2c_port,
    int sample_rate_1,
    int sample_rate_2,
    gpio_num_t pa_power_pin,
    gpio_num_t mclk_pin,
    gpio_num_t sclk_pin,
    gpio_num_t ws_pin,
    gpio_num_t data_in_pin,
    gpio_num_t data_out_pin,
    uint8_t i2c_addr,
    bool aec_enabled
) : i2c_port_(i2c_port), 
    i2c_addr_(i2c_addr),
    sample_rate_1_(sample_rate_1),
    sample_rate_2_(sample_rate_2),
    pa_power_pin_(pa_power_pin),
    aec_enabled_(aec_enabled) {

    // Initialize GPIO for power amplifier control
    gpio_config_t pa_gpio_config;
    pa_gpio_config.pin_bit_mask = (1ULL << pa_power_pin_);
    pa_gpio_config.mode = GPIO_MODE_OUTPUT;
    pa_gpio_config.pull_up_en = GPIO_PULLUP_DISABLE;
    pa_gpio_config.pull_down_en = GPIO_PULLDOWN_DISABLE;
    pa_gpio_config.intr_type = GPIO_INTR_DISABLE;
    gpio_config(&pa_gpio_config);

    // Set initial state of power amplifier to off
    gpio_set_level(pa_power_pin_, 0);

    // Initialize I2C interface for codec control
    i2c_config_t conf;
    conf.mode = I2C_MODE_MASTER;
    conf.sda_io_num = I2C_SDA_PIN;  // Assuming standard pin definitions
    conf.sda_pullup_en = GPIO_PULLUP_ENABLE;
    conf.scl_io_num = I2C_SCL_PIN;  // Assuming standard pin definitions
    conf.scl_pullup_en = GPIO_PULLUP_ENABLE;
    conf.master.clk_speed = 100000;  // 100kHz standard speed

    i2c_param_config(i2c_port_, &conf);
    i2c_driver_install(i2c_port_, conf.mode, 0, 0, 0);

    // Initialize I2S interfaces for audio data
    i2s_config_t i2s_cfg = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = (uint32_t)sample_rate_1_,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = I2S_COMM_FORMAT_I2S,
        .intr_alloc_flags = 0,
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = false,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0
    };

    i2s_pin_config_t pin_cfg = {
        .mck_io_num = mclk_pin,
        .bck_io_num = sclk_pin,
        .ws_io_num = ws_pin,
        .data_out_num = data_out_pin,
        .data_in_num = data_in_pin
    };

    // Install and configure I2S driver
    i2s_driver_install(I2S_NUM_0, &i2s_cfg, 0, NULL);
    i2s_set_pin(I2S_NUM_0, &pin_cfg);

    // Reset the codec
    es8388_write_reg(ES8388_CONTROL1, 0x80); // Reset register
    vTaskDelay(10 / portTICK_RATE_MS);
    es8388_write_reg(ES8388_CONTROL1, 0x00); // Clear reset

    // Configure power management
    es8388_write_reg(ES8388_CHIPPOWER, 0xFF); // Power down all modules initially
    es8388_write_reg(ES8388_ADCPOWER, 0xFF);  // Power down ADC
    es8388_write_reg(ES8388_DACPOWER, 0xFF);  // Power down DAC

    // Configure clock management
    es8388_write_reg(ES8388_MASTERMODE, 0x00); // Slave mode
    es8388_write_reg(ES8388_CLOCKMANAGEMENT, 0x00);

    // Set sample rate
    uint8_t sample_rate_reg = 0x00;
    switch(sample_rate_1_) {
        case 8000:  sample_rate_reg = 0x08; break;
        case 11025: sample_rate_reg = 0x10; break;
        case 16000: sample_rate_reg = 0x18; break;
        case 22050: sample_rate_reg = 0x20; break;
        case 32000: sample_rate_reg = 0x28; break;
        case 44100: sample_rate_reg = 0x30; break;
        case 48000: sample_rate_reg = 0x38; break;
        default:    sample_rate_reg = 0x30; break; // Default to 44.1kHz
    }
    es8388_write_reg(ES8388_ADCRATE, sample_rate_reg);
    es8388_write_reg(ES8388_DACRATE, sample_rate_reg);

    // Configure ADC (input)
    es8388_write_reg(ES8388_ADCCONTROL1, 0xBB); // Mono, L/R inverted
    es8388_write_reg(ES8388_ADCCONTROL2, 0x02); // LPF enable
    es8388_write_reg(ES8388_ADCCONTROL3, 0x02); // Input volume control
    es8388_write_reg(ES8388_ADCCONTROL4, 0x02); // Input gain control

    // Configure DAC (output)
    es8388_write_reg(ES8388_DACCONTROL1, 0x18); // DAC output mix enable
    es8388_write_reg(ES8388_DACCONTROL2, 0x02); // DAC volume control
    es8388_write_reg(ES8388_DACCONTROL3, 0x00); // DAC attenuation

    // Configure input channels
    es8388_write_reg(ES8388_LADCINPUT, 0x00);   // Left ADC input
    es8388_write_reg(ES8388_RADCINPUT, 0x00);   // Right ADC input

    // Configure output channels
    es8388_write_reg(ES8388_LOUT1VOL, 0x1E);    // Left output volume
    es8388_write_reg(ES8388_ROUT1VOL, 0x1E);    // Right output volume

    // Enable necessary modules
    es8388_write_reg(ES8388_CHIPPOWER, 0x00);   // Power up all modules
    es8388_write_reg(ES8388_ADCPOWER, 0x09);    // Power up ADC, MICBIAS
    es8388_write_reg(ES8388_DACPOWER, 0x30);    // Power up DAC

    // If AEC is enabled, configure reference input
    if (aec_enabled_) {
        // Configure additional input path for reference signal
        es8388_write_reg(ES8388_ADCCONTROL5, 0x01); // Enable reference input
    }

    // Start I2S peripheral
    i2s_zero_dma_buffer(I2S_NUM_0);
}

// Helper function to write to ES8388 registers
esp_err_t Es8388AudioCodec::es8388_write_reg(uint8_t reg_addr, uint8_t data) {
    i2c_cmd_handle_t cmd = i2c_cmd_link_create();
    i2c_master_start(cmd);
    i2c_master_write_byte(cmd, (i2c_addr_ << 1) | I2C_MASTER_WRITE, true);
    i2c_master_write_byte(cmd, reg_addr, true);
    i2c_master_write_byte(cmd, data, true);
    i2c_master_stop(cmd);
    esp_err_t ret = i2c_master_cmd_begin(i2c_port_, cmd, 1000 / portTICK_RATE_MS);
    i2c_cmd_link_delete(cmd);
    return ret;
}

Es8388AudioCodec::~Es8388AudioCodec()
{
    // Clean up output device resources
    if (outputDevice != nullptr) {
        outputDevice->close();
        delete outputDevice;
        outputDevice = nullptr;
    }

    // Clean up input device resources
    if (inputDevice != nullptr) {
        inputDevice->close();
        delete inputDevice;
        inputDevice = nullptr;
    }

    // Release control interface
    if (controlInterface != nullptr) {
        controlInterface->deinitialize();
        delete controlInterface;
        controlInterface = nullptr;
    }

    // Release GPIO resources
    if (gpioInterface != nullptr) {
        gpioInterface->releaseAllPins();
        gpioInterface->deinitialize();
        delete gpioInterface;
        gpioInterface = nullptr;
    }

    // Close and release data interface
    if (dataInterface != nullptr) {
        dataInterface->close();
        dataInterface->deinitialize();
        delete dataInterface;
        dataInterface = nullptr;
    }

    // Release any additional hardware resources
    if (hardwareHandle != nullptr) {
        // Perform hardware-specific cleanup
        releaseHardwareResources();
        hardwareHandle = nullptr;
    }

    // Free any allocated buffers or memory
    if (audioBuffer != nullptr) {
        delete[] audioBuffer;
        audioBuffer = nullptr;
    }

    // Reset configuration state
    isInitialized = false;
    isRunning = false;

    // Log successful cleanup if logging is enabled
    #ifdef ENABLE_AUDIO_LOGGING
    logMessage("ES8388 Audio Codec resources successfully released");
    #endif
}

esp_err_t CreateDuplexChannels(gpio_num_t bck_pin, gpio_num_t ws_pin, gpio_num_t data_out_pin, gpio_num_t data_in_pin, gpio_num_t mclk_pin)
{
    // Configure I2S driver for full-duplex operation
    i2s_driver_config_t i2s_config = {
        .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_TX | I2S_MODE_RX),
        .sample_rate = 44100,
        .bits_per_sample = I2S_BITS_PER_SAMPLE_16BIT,
        .channel_format = I2S_CHANNEL_FMT_RIGHT_LEFT,
        .communication_format = I2S_COMM_FORMAT_I2S,
        .intr_alloc_flags = 0,
        .dma_buf_count = 8,
        .dma_buf_len = 64,
        .use_apll = true,
        .tx_desc_auto_clear = true,
        .fixed_mclk = 0,
        .mclk_multiple = I2S_MCLK_MULTIPLE_256,
        .bits_per_chan = I2S_BITS_PER_CHAN_16BIT,
    };

    // Install and start I2S driver
    esp_err_t ret = i2s_driver_install(I2S_NUM_0, &i2s_config, 0, NULL);
    if (ret != ESP_OK) {
        return ret;
    }

    // Configure I2S pin mapping
    i2s_pin_config_t pin_config = {
        .mck_io_num = mclk_pin,
        .bck_io_num = bck_pin,
        .ws_io_num = ws_pin,
        .data_out_num = data_out_pin,
        .data_in_num = data_in_pin
    };

    ret = i2s_set_pin(I2S_NUM_0, &pin_config);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Set clock configuration
    ret = i2s_set_clk(I2S_NUM_0, 44100, I2S_BITS_PER_SAMPLE_16BIT, I2S_CHANNEL_STEREO);
    if (ret != ESP_OK) {
        i2s_driver_uninstall(I2S_NUM_0);
        return ret;
    }

    // Zero-initialize the DMA buffers to prevent noise
    i2s_zero_dma_buffer(I2S_NUM_0);

    return ESP_OK;
}

void SetOutputVolume(int volumeLevel) {
    // Validate volume level range (assuming 0-100 scale)
    if (volumeLevel < 0) {
        volumeLevel = 0;
    } else if (volumeLevel > 100) {
        volumeLevel = 100;
    }

    // Store current volume level in internal state
    static int currentVolume = 0;
    currentVolume = volumeLevel;

    // Convert volume level to ES8388 register format
    // ES8388 typically uses 0-255 range for volume control
    uint8_t dacVolume = (uint8_t)((volumeLevel * 255) / 100);

    // ES8388 codec register addresses for DAC volume control
    const uint8_t ES8388_DACCONTROL4 = 0x04;  // Left DAC volume control
    const uint8_t ES8388_DACCONTROL5 = 0x05;  // Right DAC volume control

    // Write volume settings to ES8388 codec registers
    // Assuming there's a function to write to codec registers
    // Write left channel volume
    WriteCodecRegister(ES8388_DACCONTROL4, dacVolume);

    // Write right channel volume  
    WriteCodecRegister(ES8388_DACCONTROL5, dacVolume);

    // Optional: Add mute/unmute control based on volume level
    if (volumeLevel == 0) {
        // Mute DAC outputs
        WriteCodecRegister(0x02, 0x40); // DACCONTROL2 - Mute both channels
    } else {
        // Unmute DAC outputs if previously muted
        WriteCodecRegister(0x02, 0x00); // DACCONTROL2 - Unmute both channels
    }
}

// Helper function prototype (assumed to exist in the system)
