void EnableInput(bool enable) {
    if (enable) {
        // Configure ES8388 input registers
        // Set ADC power control
        WriteRegister(ES8388_ADCPOWER, 0x00); // Power up ADC

        // Configure ADC control registers
        WriteRegister(ES8388_ADCCONTROL1, 0x00); // ADC digital microphone off, normal mode
        WriteRegister(ES8388_ADCCONTROL2, 0x00); // ADC soft reset off, MCLK/LRCK ratio

        // Set sample rate and format
        WriteRegister(ES8388_ADCCONTROL3, 0x02); // ADC sample rate
        WriteRegister(ES8388_ADCCONTROL4, 0x00); // ADC format: I2S, 16-bit

        // Configure input gain
        WriteRegister(ES8388_ADCCONTROL5, 0x20); // ADC volume control - left channel
        WriteRegister(ES8388_ADCCONTROL6, 0x20); // ADC volume control - right channel

        // Configure microphone input
        WriteRegister(ES8388_ADCCONTROL7, 0x00); // ADC L/R channel PGA gain
        WriteRegister(ES8388_ADCCONTROL8, 0x00); // ADC mute, PGA gain control

        // Select input source (mic/line-in)
        WriteRegister(ES8388_ADCCONTROL9, 0x01); // Select microphone input

        // Unmute ADC
        WriteRegister(ES8388_ADCCONTROL10, 0x00); // Unmute ADC output

        // Open input device for audio capture
        OpenInputDevice();

        // Apply additional gain settings if needed
        ApplyInputGain();
    } else {
        // Mute ADC before shutting down
        WriteRegister(ES8388_ADCCONTROL10, 0xC0); // Mute ADC output

        // Power down ADC
        WriteRegister(ES8388_ADCPOWER, 0xFF); // Power down ADC

        // Close input device to stop audio capture
        CloseInputDevice();
    }
}

void EnableOutput(bool enable) {
    if (enable) {
        // Enable the codec output
        // Configure sample rate settings
        ES8388_WriteReg(ES8388_DACCONTROL1, 0x00); // DAC oversampling frequency ratio
        ES8388_WriteReg(ES8388_DACCONTROL2, 0x02); // DAC MCLK/LRCK ratio
        ES8388_WriteReg(ES8388_DACCONTROL3, 0x00); // DAC path selection

        // Configure volume settings
        ES8388_WriteReg(ES8388_DACCONTROL4, 0x1E); // Left DAC volume
        ES8388_WriteReg(ES8388_DACCONTROL5, 0x1E); // Right DAC volume

        // Set analog output levels
        ES8388_WriteReg(ES8388_ANAVOLMANAG, 0x00); // Analog volume management
        ES8388_WriteReg(ES8388_MASTERMODE, 0x00);  // Master volume control

        // Enable DAC and analog output
        ES8388_WriteReg(ES8388_CHIPPOWER, 0x00);   // Power up DAC and analog blocks
        ES8388_WriteReg(ES8388_DACPOWER, 0xC0);    // Power up DAC L/R channels

        // Configure output mixer
        ES8388_WriteReg(ES8388_DACCONTROL16, 0x00); // Left channel mixer
        ES8388_WriteReg(ES8388_DACCONTROL17, 0x00); // Right channel mixer

        // Activate power amplifier pin if present
        #ifdef POWER_AMP_PIN
        digitalWrite(POWER_AMP_PIN, HIGH);
        pinMode(POWER_AMP_PIN, OUTPUT);
        #endif

        // Enable I2S output
        ES8388_WriteReg(ES8388_MASTERMODE, 0x00);  // Set master mode
    } else {
        // Disable the codec output
        // Close codec output device
        ES8388_WriteReg(ES8388_DACPOWER, 0xFF);    // Power down DAC L/R channels
        ES8388_WriteReg(ES8388_CHIPPOWER, 0xFF);   // Power down all blocks

        // Deactivate power amplifier pin if present
        #ifdef POWER_AMP_PIN
        digitalWrite(POWER_AMP_PIN, LOW);
        #endif
    }
}

int Es8388AudioCodec::Read(int16_t* buffer, int samples) {
    // Check if input is enabled before reading
    if (!IsInputEnabled()) {
        return 0; // Return 0 samples if input is not enabled
    }

    // Validate input parameters
    if (buffer == nullptr || samples <= 0) {
        return 0;
    }

    // Use ESP-IDF codec device API to read audio data
    // Assuming there's a codec handle available as member variable
    size_t bytes_to_read = samples * sizeof(int16_t);
    size_t bytes_read = 0;

    // Call the ESP-IDF codec read function
    esp_err_t result = codec_dev_read(m_codec_handle, reinterpret_cast<uint8_t*>(buffer), bytes_to_read, &bytes_read);

    if (result != ESP_OK) {
        return 0; // Return 0 on error
    }

    // Convert bytes read back to samples
    int samples_read = static_cast<int>(bytes_read / sizeof(int16_t));

    return samples_read;
}

int Write(const int16_t* data, int sampleCount) {
    // Check if data pointer is valid
    if (data == nullptr) {
        return 0;
    }

    // Check if output is enabled
    if (!outputEnabled) {
        return 0;
    }

    // Check if device is valid
    if (!deviceValid) {
        return 0;
    }

    // Check for valid sample count
    if (sampleCount <= 0) {
        return 0;
    }

    // Convert sample count to byte size (int16_t = 2 bytes per sample)
    int byteSize = sampleCount * sizeof(int16_t);

    // Send data to ES8388 codec
    // Assuming there's a lower-level function to handle the actual transmission
    int result = es8388_write_data(reinterpret_cast<const uint8_t*>(data), byteSize);

    // If transmission was successful, return the number of samples written
    // Otherwise return 0
    if (result == byteSize) {
        return sampleCount;
    } else {
        return 0;
    }
}

AudioDebugger::AudioDebugger() {
    // Initialize member variables
    m_udpSocket = -1;
    m_isInitialized = false;
    m_serverPort = 0;

    // Get configuration settings for server IP and port
    std::string serverIP = getConfigServerIP();
    m_serverPort = getConfigServerPort();

    // Validate configuration parameters
    if (serverIP.empty() || m_serverPort == 0) {
        logError("Invalid server configuration: IP or port not set");
        return;
    }

    // Create UDP socket
    m_udpSocket = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (m_udpSocket < 0) {
        logError("Failed to create UDP socket: " + std::string(strerror(errno)));
        return;
    }

    // Configure server address structure
    memset(&m_serverAddr, 0, sizeof(m_serverAddr));
    m_serverAddr.sin_family = AF_INET;
    m_serverAddr.sin_port = htons(m_serverPort);

    // Parse and set server IP address
    if (inet_pton(AF_INET, serverIP.c_str(), &m_serverAddr.sin_addr) <= 0) {
        logError("Failed to parse server IP address: " + serverIP);
        close(m_udpSocket);
        m_udpSocket = -1;
        return;
    }

    // Test connection by sending a simple debug message
    const char* testMessage = "AudioDebugger initialized";
    ssize_t sentBytes = sendto(m_udpSocket, testMessage, strlen(testMessage), 
                              0, (struct sockaddr*)&m_serverAddr, sizeof(m_serverAddr));

    if (sentBytes < 0) {
        logError("Failed to send test message to server: " + std::string(strerror(errno)));
        close(m_udpSocket);
        m_udpSocket = -1;
        return;
    }

    // Mark as successfully initialized
    m_isInitialized = true;
    logInfo("AudioDebugger successfully initialized. Connected to " + serverIP + ":" + std::to_string(m_serverPort));
}

AudioDebugger::~AudioDebugger()
{
    // Only execute cleanup when audio debugger feature is enabled
    if (config.isAudioDebuggerEnabled()) {
        // Log the cleanup action for debugging purposes
        Logger::debug("AudioDebugger: Cleaning up UDP socket resources");

        try {
            // Clean up the UDP socket resource
            if (udpSocket) {
                udpSocket->close();
                delete udpSocket;
                udpSocket = nullptr;
            }

            // Log successful cleanup
            Logger::debug("AudioDebugger: UDP socket cleanup completed successfully");
        }
        catch (const std::exception& e) {
            // Log any errors during cleanup but don't let exceptions escape destructor
            Logger::error("AudioDebugger: Error during UDP socket cleanup: " + std::string(e.what()));
        }
        catch (...) {
            // Handle any other unexpected exceptions
            Logger::error("AudioDebugger: Unknown error during UDP socket cleanup");
        }
    }
}

void AudioDebugger::Feed(const std::vector<int16_t>& samples) {
#ifdef ENABLE_AUDIO_DEBUGGING
    if (samples.empty()) {
        LOG_WARNING("AudioDebugger: Empty samples vector provided");
        return;
    }

    // Convert int16_t samples to raw bytes
    const size_t data_size = samples.size() * sizeof(int16_t);
    const char* raw_data = reinterpret_cast<const char*>(samples.data());

    // Send data over UDP
    int bytes_sent = sendto(udp_socket_, raw_data, data_size, 0,
                           reinterpret_cast<struct sockaddr*>(&server_addr_),
                           sizeof(server_addr_));

    // Log the result
    if (bytes_sent < 0) {
        LOG_ERROR("AudioDebugger: Failed to send audio data over UDP. Error: %d", errno);
    } else if (static_cast<size_t>(bytes_sent) != data_size) {
        LOG_WARNING("AudioDebugger: Incomplete data transmission. Sent %d/%zu bytes", 
                   bytes_sent, data_size);
    } else {
        LOG_DEBUG("AudioDebugger: Successfully sent %zu audio samples (%zu bytes)", 
                 samples.size(), data_size);
    }
#else
    // Audio debugging disabled - empty implementation
    (void)samples; // Suppress unused parameter warning
#endif
}

