void AfeWakeWord::AudioDetectionTask() {
    // Initialize detection state
    bool detectionRunning = true;
    WakeWordDetectedCallback callback = this->wakeWordCallback;

    // Ensure AFE is properly initialized
    if (!afeInterface || !callback) {
        return;
    }

    // Main detection loop
    while (detectionRunning && !shutdownRequested) {
        // Read audio data from input stream
        AudioBuffer audioData;
        AudioResult result = audioInputStream->Read(audioData);

        if (result != AUDIO_SUCCESS) {
            // Handle audio read errors
            if (result == AUDIO_DISCONNECTED) {
                break; // Exit if audio source is disconnected
            }
            continue; // Skip this iteration on other errors
        }

        // Feed audio data to acoustic front-end for processing
        AfeResult afeResult = afeInterface->ProcessAudio(audioData);

        if (afeResult != AFE_SUCCESS) {
            continue; // Skip if AFE processing failed
        }

        // Check if wake word was detected
        WakeWordDetectionInfo detectionInfo;
        if (afeInterface->IsWakeWordDetected(detectionInfo)) {
            // Stop the detection process
            detectionRunning = false;

            // Store relevant audio data (pre-roll/buffered audio)
            AudioBuffer wakeWordAudio;
            if (afeInterface->GetWakeWordAudio(wakeWordAudio)) {
                // Store the audio data for further processing
                storedAudioData = wakeWordAudio;
            }

            // Extract wake word information
            std::string detectedWakeWord = detectionInfo.wakeWord;
            uint32_t timestamp = detectionInfo.timestamp;
            float confidence = detectionInfo.confidence;

            // Validate wake word before triggering callback
            if (!detectedWakeWord.empty() && confidence >= MIN_CONFIDENCE_THRESHOLD) {
                // Trigger callback with detected wake word information
                WakeWordEvent event;
                event.wakeWord = detectedWakeWord;
                event.timestamp = timestamp;
                event.confidence = confidence;
                event.audioData = wakeWordAudio;

                // Call the registered callback
                callback(event);
            }
        }

        // Optional: Add small delay to prevent busy waiting
        // This allows other threads/system tasks to execute
        if (detectionRunning) {
            Thread::Sleep(DETECTION_LOOP_DELAY_MS);
        }
    }

    // Cleanup resources if shutdown was requested
    if (shutdownRequested) {
        afeInterface->Stop();
        audioInputStream->Close();
    }
}

void AfeWakeWord::StoreWakeWordData(const int16_t* audioData, size_t dataLength) {
    // Validate input parameters
    if (audioData == nullptr || dataLength == 0) {
        return;
    }

    // Assuming standard 16kHz sampling rate, 2 seconds = 32000 samples
    // For 16-bit audio: 32000 samples * 2 bytes = 64KB buffer
    const size_t MAX_BUFFER_SAMPLES = 32000; // 2 seconds at 16kHz

    // Ensure we have adequate buffer space
    if (m_wakeWordBuffer.capacity() < MAX_BUFFER_SAMPLES) {
        m_wakeWordBuffer.reserve(MAX_BUFFER_SAMPLES);
    }

    // Add new audio data to the end of buffer
    for (size_t i = 0; i < dataLength; ++i) {
        m_wakeWordBuffer.push_back(audioData[i]);
    }

    // Remove excess old data if buffer exceeds 2 seconds
    if (m_wakeWordBuffer.size() > MAX_BUFFER_SAMPLES) {
        // Calculate how many samples to remove
        size_t excessSamples = m_wakeWordBuffer.size() - MAX_BUFFER_SAMPLES;

        // Remove oldest samples from the beginning
        m_wakeWordBuffer.erase(m_wakeWordBuffer.begin(), 
                              m_wakeWordBuffer.begin() + excessSamples);
    }
}

bool AfeWakeWord::EncodeWakeWordData(const int16_t* pcmData, size_t pcmSize, uint32_t sampleRate, uint8_t channels)
{
    if (!pcmData || pcmSize == 0) {
        return false;
    }

    // Allocate memory for task stack (prefer SPIRAM if available)
    void* taskStack = nullptr;
    const size_t stackSize = 8192; // 8KB stack for encoding task

    #ifdef CONFIG_SPIRAM_SUPPORT
        taskStack = heap_caps_malloc(stackSize, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
    #endif

    if (!taskStack) {
        taskStack = malloc(stackSize);
        if (!taskStack) {
            return false;
        }
    }

    // Initialize Opus encoder with low complexity settings
    int opusError = 0;
    OpusEncoder* encoder = opus_encoder_create(sampleRate, channels, OPUS_APPLICATION_VOIP, &opusError);
    if (opusError != OPUS_OK || !encoder) {
        free(taskStack);
        return false;
    }

    // Set low complexity for fast encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(OPUS_AUTO));
    opus_encoder_ctl(encoder, OPUS_SET_VBR(1));

    // Prepare encoding parameters
    const int frameSize = sampleRate * 0.02f; // 20ms frames
    const int maxPacketSize = 4000;
    std::vector<uint8_t> encodedBuffer(maxPacketSize);

    // Thread-safe buffer for encoded data
    static std::mutex encodeMutex;
    static std::condition_variable encodeComplete;
    static std::queue<std::vector<uint8_t>> encodedPackets;
    static bool encodingFinished = false;

    // Encoding task function
    auto encodingTask = [this, encoder, pcmData, pcmSize, frameSize, maxPacketSize, 
                        &encodedBuffer, &encodeMutex, &encodeComplete, &encodedPackets, &encodingFinished]() {

        size_t samplesProcessed = 0;
        const size_t totalSamples = pcmSize / sizeof(int16_t);
        const int16_t* pcmPtr = pcmData;

        while (samplesProcessed < totalSamples) {
            int samplesToProcess = std::min(frameSize, static_cast<int>(totalSamples - samplesProcessed));

            // Encode PCM frame to Opus
            int encodedBytes = opus_encode(encoder, pcmPtr + samplesProcessed, samplesToProcess,
                                         encodedBuffer.data(), maxPacketSize);

            if (encodedBytes > 0) {
                // Store encoded packet in thread-safe buffer
                std::lock_guard<std::mutex> lock(encodeMutex);
                std::vector<uint8_t> packet(encodedBuffer.begin(), encodedBuffer.begin() + encodedBytes);
                encodedPackets.push(packet);
            }

            samplesProcessed += samplesToProcess;
        }

        // Signal completion
        {
            std::lock_guard<std::mutex> lock(encodeMutex);
            encodingFinished = true;
        }
        encodeComplete.notify_all();
    };

    // Create real-time encoding task
    TaskHandle_t encodingTaskHandle = nullptr;
    BaseType_t result = xTaskCreate(encodingTask, "OpusEncodingTask", 
                                   stackSize / sizeof(StackType_t), 
                                   nullptr, 
                                   configMAX_PRIORITIES - 1, // High priority for real-time processing
                                   &encodingTaskHandle);

    if (result != pdPASS) {
        opus_encoder_destroy(encoder);
        free(taskStack);
        return false;
    }

    // Wait for encoding completion with timeout
    std::unique_lock<std::mutex> lock(encodeMutex);
    if (encodeComplete.wait_for(lock, std::chrono::milliseconds(5000), [&](){ return encodingFinished; })) {
        // Encoding completed successfully
        // Here you would typically process the encodedPackets queue
        // For example: transfer to main buffer or send to network

        // Cleanup
        if (encodingTaskHandle) {
            vTaskDelete(encodingTaskHandle);
        }
        opus_encoder_destroy(encoder);

        // Free task stack memory
        #ifdef CONFIG_SPIRAM_SUPPORT
            heap_caps_free(taskStack);
        #else
            free(taskStack);
        #endif

        return true;
    } else {
        // Timeout occurred
        if (encodingTaskHandle) {
            vTaskDelete(encodingTaskHandle);
        }
        opus_encoder_destroy(encoder);

        #ifdef CONFIG_SPIRAM_SUPPORT
            heap_caps_free(taskStack);
        #else
            free(taskStack);
        #endif

        return false;
    }
}

bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opusData) {
    // Acquire lock for thread-safe access to the wake word queue
    std::unique_lock<std::mutex> lock(m_wakeWordMutex);

    // Wait until wake word data is available in the queue
    // This blocks the calling thread until the condition is met
    m_wakeWordCondition.wait(lock, [this]() {
        return !m_wakeWordQueue.empty();
    });

    // Check if there's actually data available (defensive programming)
    if (m_wakeWordQueue.empty()) {
        return false;
    }

    // Retrieve the front element from the queue
    opusData = std::move(m_wakeWordQueue.front());
    m_wakeWordQueue.pop_front();

    // Return success
    return true;
}

