bool CustomWakeWord::ParseWakenetModelConfig(const std::string& configPath) {
    try {
        // Read the JSON configuration file
        std::ifstream configFile(configPath);
        if (!configFile.is_open()) {
            ESP_LOGE(TAG, "Failed to open configuration file: %s", configPath.c_str());
            return false;
        }

        // Parse JSON content
        json configJson;
        configFile >> configJson;
        configFile.close();

        // Extract language setting
        if (configJson.contains("language")) {
            m_language = configJson["language"].get<std::string>();
            ESP_LOGI(TAG, "Language configured: %s", m_language.c_str());
        } else {
            ESP_LOGW(TAG, "Language not specified in configuration, using default");
            m_language = "en"; // Default to English
        }

        // Extract duration setting
        if (configJson.contains("duration")) {
            m_duration = configJson["duration"].get<int>();
            ESP_LOGI(TAG, "Duration configured: %d seconds", m_duration);
        } else {
            ESP_LOGW(TAG, "Duration not specified in configuration, using default");
            m_duration = 3; // Default to 3 seconds
        }

        // Extract threshold setting
        if (configJson.contains("threshold")) {
            m_threshold = configJson["threshold"].get<float>();
            ESP_LOGI(TAG, "Threshold configured: %.2f", m_threshold);
        } else {
            ESP_LOGW(TAG, "Threshold not specified in configuration, using default");
            m_threshold = 0.5f; // Default threshold
        }

        // Extract and parse command definitions
        if (configJson.contains("commands") && configJson["commands"].is_array()) {
            m_commands.clear();
            auto commandsArray = configJson["commands"];

            for (const auto& command : commandsArray) {
                if (command.contains("name") && command.contains("id")) {
                    WakeWordCommand cmd;
                    cmd.name = command["name"].get<std::string>();
                    cmd.id = command["id"].get<int>();

                    // Optional confidence threshold per command
                    if (command.contains("threshold")) {
                        cmd.threshold = command["threshold"].get<float>();
                    } else {
                        cmd.threshold = m_threshold; // Use global threshold
                    }

                    m_commands.push_back(cmd);

                    // Log the parsed command for debugging
                    ESP_LOGI(TAG, "Parsed command: %s (ID: %d, Threshold: %.2f)", 
                             cmd.name.c_str(), cmd.id, cmd.threshold);
                } else {
                    ESP_LOGW(TAG, "Skipping invalid command definition in configuration");
                }
            }

            ESP_LOGI(TAG, "Total commands loaded: %d", m_commands.size());
        } else {
            ESP_LOGW(TAG, "No valid commands found in configuration");
            m_commands.clear();
        }

        // Additional model-specific configurations
        if (configJson.contains("model_version")) {
            m_modelVersion = configJson["model_version"].get<std::string>();
            ESP_LOGI(TAG, "Model version: %s", m_modelVersion.c_str());
        }

        if (configJson.contains("sample_rate")) {
            m_sampleRate = configJson["sample_rate"].get<int>();
            ESP_LOGI(TAG, "Sample rate configured: %d Hz", m_sampleRate);
        }

        // Mark configuration as loaded successfully
        m_isConfigLoaded = true;
        ESP_LOGI(TAG, "Wakenet model configuration loaded successfully from %s", configPath.c_str());

        return true;

    } catch (const json::exception& e) {
        ESP_LOGE(TAG, "JSON parsing error: %s", e.what());
        return false;
    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "Error parsing wakenet configuration: %s", e.what());
        return false;
    } catch (...) {
        ESP_LOGE(TAG, "Unknown error occurred while parsing configuration");
        return false;
    }
}

bool CustomWakeWord::Initialize(AudioCodec* audioCodec, srmodel_list_t* modelList) {
    // Validate input parameters
    if (audioCodec == nullptr || modelList == nullptr) {
        return false;
    }

    // Configure the audio codec for wake word detection
    if (!audioCodec->initialize()) {
        return false;
    }

    // Set audio parameters for wake word detection
    if (!audioCodec->setSampleRate(WAKE_WORD_SAMPLE_RATE)) {
        return false;
    }

    if (!audioCodec->setChannelCount(WAKE_WORD_CHANNEL_COUNT)) {
        return false;
    }

    if (!audioCodec->setBitDepth(WAKE_WORD_BIT_DEPTH)) {
        return false;
    }

    // Load voice recognition models from the model list
    if (!loadRecognitionModels(modelList)) {
        return false;
    }

    // Initialize the multinet model for speech command recognition
    if (!initializeMultinetModel()) {
        return false;
    }

    // Register custom voice commands
    if (!registerCustomCommands()) {
        return false;
    }

    // Apply language settings
    if (!configureLanguageSettings()) {
        return false;
    }

    // Apply threshold settings for wake word detection
    if (!configureThresholdSettings()) {
        return false;
    }

    // Start audio capture for wake word detection
    if (!audioCodec->startCapture()) {
        return false;
    }

    // Mark initialization as complete
    m_initialized = true;

    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t>& audioData) {
    // Check if detection is currently active
    if (!m_isActive) {
        return;
    }

    // Handle empty input
    if (audioData.empty()) {
        return;
    }

    // Process audio data based on channel configuration
    std::vector<int16_t> processedAudio;
    if (m_isStereo) {
        // Extract left channel from stereo input (every other sample)
        processedAudio.reserve(audioData.size() / 2);
        for (size_t i = 0; i < audioData.size(); i += 2) {
            processedAudio.push_back(audioData[i]);
        }
    } else {
        // Mono input - use as is
        processedAudio = audioData;
    }

    // Append to internal buffer
    m_audioBuffer.insert(m_audioBuffer.end(), processedAudio.begin(), processedAudio.end());

    // Process buffered audio through multinet model
    while (m_audioBuffer.size() >= m_frameSize) {
        // Extract a frame for processing
        std::vector<int16_t> frame(m_audioBuffer.begin(), m_audioBuffer.begin() + m_frameSize);

        // Run wake word detection on the frame
        int detectedWordId = m_multinetModel->detect(frame);

        // Check if a wake word was detected
        if (detectedWordId >= 0 && detectedWordId < static_cast<int>(m_wakeWords.size())) {
            // Wake word detected - trigger callback
            if (m_detectionCallback) {
                m_detectionCallback(m_wakeWords[detectedWordId]);
            }

            // Deactivate detection until reactivated
            m_isActive = false;

            // Clear buffer to start fresh after reactivation
            m_audioBuffer.clear();

            return;
        }

        // Remove processed portion from buffer (with overlap for continuity)
        size_t removeSize = m_frameSize - m_frameOverlap;
        if (m_audioBuffer.size() > removeSize) {
            m_audioBuffer.erase(m_audioBuffer.begin(), m_audioBuffer.begin() + removeSize);
        } else {
            m_audioBuffer.clear();
        }
    }
}

