    return m_feedSize;
}

void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& audioChunk) {
    // Define constants
    const int SAMPLE_RATE = 16000;  // 16kHz sample rate
    const size_t MAX_BUFFER_SIZE = 2 * SAMPLE_RATE;  // 2 seconds of audio data

    // Add new audio data to the end of the buffer
    for (const auto& sample : audioChunk) {
        m_audioBuffer.push_back(sample);
    }

    // Remove old data if buffer exceeds 2 seconds
    while (m_audioBuffer.size() > MAX_BUFFER_SIZE) {
        m_audioBuffer.pop_front();
    }
}

bool EncodeWakeWordData()
{
    // Configuration parameters
    const int OPUS_SAMPLE_RATE = 16000;
    const int OPUS_CHANNELS = 1;
    const int OPUS_FRAME_SIZE = 960; // 60ms at 16kHz
    const int OPUS_BITRATE = 24000;
    const int STACK_SIZE = 8192;
    const int BUFFER_SIZE = 4096;

    // Memory allocation for task stack and buffer
    uint8_t* taskStack = (uint8_t*)malloc(STACK_SIZE);
    if (!taskStack) {
        return false;
    }

    uint8_t* encodeBuffer = (uint8_t*)malloc(BUFFER_SIZE);
    if (!encodeBuffer) {
        free(taskStack);
        return false;
    }

    // Initialize Opus encoder with low complexity settings
    int opusError = 0;
    OpusEncoder* encoder = opus_encoder_create(OPUS_SAMPLE_RATE, OPUS_CHANNELS, OPUS_APPLICATION_VOIP, &opusError);
    if (opusError != OPUS_OK || !encoder) {
        free(taskStack);
        free(encodeBuffer);
        return false;
    }

    // Set low complexity encoding
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(OPUS_BITRATE));
    opus_encoder_ctl(encoder, OPUS_SET_VBR(1));

    // Create background task to handle encoding
    // Using a lambda to capture necessary variables
    auto encodingTask = [encoder, encodeBuffer, taskStack]() {
        // Get access to stored PCM data (assuming it's globally accessible or passed)
        extern std::vector<int16_t> storedPcmData;
        extern std::vector<uint8_t> encodedOpusData;
        extern std::mutex encodedDataMutex;
        extern std::condition_variable encodingComplete;
        extern bool encodingFinished;

        size_t pcmIndex = 0;
        std::lock_guard<std::mutex> lock(encodedDataMutex);

        // Process PCM data in frames
        while (pcmIndex + OPUS_FRAME_SIZE <= storedPcmData.size()) {
            // Encode one frame of PCM data
            int encodedBytes = opus_encode(encoder, 
                                         &storedPcmData[pcmIndex], 
                                         OPUS_FRAME_SIZE, 
                                         encodeBuffer, 
                                         BUFFER_SIZE);

            if (encodedBytes > 0) {
                // Append encoded data to output buffer
                encodedOpusData.insert(encodedOpusData.end(), encodeBuffer, encodeBuffer + encodedBytes);
            }

            pcmIndex += OPUS_FRAME_SIZE;
        }

        // Append termination marker (using Opus TOC for self-delimiting)
        // Simple approach: add zero-length frame as termination
        uint8_t terminationMarker[1] = {0};
        encodedOpusData.push_back(terminationMarker[0]);

        // Cleanup encoder
        opus_encoder_destroy(encoder);

        // Signal completion
        encodingFinished = true;
        encodingComplete.notify_all();

        // Free allocated memory
        free(encodeBuffer);
        free(taskStack);
    };

    // Spawn background thread for encoding
    try {
        std::thread encodingThread(encodingTask);
        encodingThread.detach(); // Run in background
    } catch (...) {
        // Cleanup on failure
        opus_encoder_destroy(encoder);
        free(encodeBuffer);
        free(taskStack);
        return false;
    }

    return true;
}

bool GetWakeWordOpus(std::vector<uint8_t>& opusData) {
    std::unique_lock<std::mutex> lock(m_mutex);

    // Wait until data is available in the queue
    m_conditionVariable.wait(lock, [this]() { 
        return !m_wakeWordQueue.empty(); 
    });

    // Retrieve the data by swapping to minimize copies
    opusData.swap(m_wakeWordQueue.front());

    // Remove the processed element
    m_wakeWordQueue.pop();

    // Return success based on whether the retrieved data is non-empty
    return !opusData.empty();
}

void XL9555(i2c_master_bus_handle_t i2c_bus, uint8_t address)
{
    // Configuration data for the XL9555
    // Register 0x06: Configuration Port 0 (0 = output, 1 = input)
    // Register 0x07: Configuration Port 1 (0 = output, 1 = input)

    // Example configuration: All pins as outputs (0x00)
    uint8_t config_port0 = 0x00;  // All pins of port 0 as outputs
    uint8_t config_port1 = 0x00;  // All pins of port 1 as outputs

    // Set default output states (all low)
    uint8_t output_port0 = 0x00;
    uint8_t output_port1 = 0x00;

    // Buffer for I2C writes
    uint8_t write_buffer[2];

    // Configure Port 0 direction (register 0x06)
    write_buffer[0] = 0x06;  // Register address
    write_buffer[1] = config_port0;  // Configuration value
    i2c_master_transmit(i2c_bus, address, write_buffer, 2, -1);

    // Configure Port 1 direction (register 0x07)
    write_buffer[0] = 0x07;  // Register address
    write_buffer[1] = config_port1;  // Configuration value
    i2c_master_transmit(i2c_bus, address, write_buffer, 2, -1);

    // Set initial output states for Port 0 (register 0x02)
    write_buffer[0] = 0x02;  // Register address
    write_buffer[1] = output_port0;  // Output value
    i2c_master_transmit(i2c_bus, address, write_buffer, 2, -1);

    // Set initial output states for Port 1 (register 0x03)
    write_buffer[0] = 0x03;  // Register address
    write_buffer[1] = output_port1;  // Output value
    i2c_master_transmit(i2c_bus, address, write_buffer, 2, -1);

    // Optional: Configure polarity inversion registers (0x04 and 0x05)
    // Typically set to 0x00 for normal polarity
    write_buffer[0] = 0x04;  // Register address
    write_buffer[1] = 0x00;  // Normal polarity for Port 0
    i2c_master_transmit(i2c_bus, address, write_buffer, 2, -1);

    write_buffer[0] = 0x05;  // Register address
    write_buffer[1] = 0x00;  // Normal polarity for Port 1
    i2c_master_transmit(i2c_bus, address, write_buffer, 2, -1);
}

void SetOutputState(uint8_t pinNumber, uint8_t level)
{
    // Define the base address of the output register (example address)
    volatile uint8_t* OUTPUT_REGISTER = (volatile uint8_t*)0x1000;

    // Read the current value of the output register
    uint8_t currentValue = *OUTPUT_REGISTER;

    // Validate pin number (assuming 8-bit register, pins 0-7)
    if (pinNumber > 7) {
        return; // Invalid pin number
    }

    if (level != 0) {
        // Set the specified bit (set pin high)
        currentValue |= (1 << pinNumber);
    } else {
        // Clear the specified bit (set pin low)
        currentValue &= ~(1 << pinNumber);
    }

    // Write the modified value back to the register
    *OUTPUT_REGISTER = currentValue;
}

void InitializeI2c() {
    // Initialize I2C bus as master
    Wire.begin();

    // Set I2C clock speed (typically 100kHz or 400kHz)
    Wire.setClock(100000); // 100kHz standard mode

    // Configure XL9555 I/O expander at address 0x20
    // XL9555 has several registers:
    // Register 0x06: Input Port 0
    // Register 0x07: Input Port 1
    // Register 0x02: Output Port 0
    // Register 0x03: Output Port 1
    // Register 0x04: Polarity Inversion Port 0
    // Register 0x05: Polarity Inversion Port 1
    // Register 0x00: Configuration Port 0 (1 = input, 0 = output)
    // Register 0x01: Configuration Port 1 (1 = input, 0 = output)

    // Configure all pins as outputs initially (0x00 = all outputs)
    Wire.beginTransmission(0x20);
    Wire.write(0x00); // Configuration register Port 0
    Wire.write(0x00); // All pins as outputs
    Wire.endTransmission();

    Wire.beginTransmission(0x20);
    Wire.write(0x01); // Configuration register Port 1
    Wire.write(0x00); // All pins as outputs
    Wire.endTransmission();

    // Disable polarity inversion (default)
    Wire.beginTransmission(0x20);
    Wire.write(0x04); // Polarity register Port 0
    Wire.write(0x00); // No inversion
    Wire.endTransmission();

    Wire.beginTransmission(0x20);
    Wire.write(0x05); // Polarity register Port 1
    Wire.write(0x00); // No inversion
    Wire.endTransmission();

    // Initialize output ports to low state
    Wire.beginTransmission(0x20);
    Wire.write(0x02); // Output Port 0
    Wire.write(0x00); // All outputs low
    Wire.endTransmission();

    Wire.beginTransmission(0x20);
    Wire.write(0x03); // Output Port 1
    Wire.write(0x00); // All outputs low
    Wire.endTransmission();
}

