float FrequencyDetector::ProcessSample(float input) {
    // Apply the second-order IIR filter difference equation
    // y[n] = b0*x[n] + b1*x[n-1] + b2*x[n-2] - a1*y[n-1] - a2*y[n-2]

    float output = b0_ * input + 
                   b1_ * x1_ + 
                   b2_ * x2_ - 
                   a1_ * y1_ - 
                   a2_ * y2_;

    // Update the state buffer for next iteration
    // Shift previous input samples
    x2_ = x1_;
    x1_ = input;

    // Shift previous output samples
    y2_ = y1_;
    y1_ = output;

    return output;
}

