    }

    // Compute real and imaginary parts using cosine and sine coefficients
    float real_part = sample_n * cos_coefficient + sample_n1 * cos_coefficient_prev;
    float imag_part = sample_n * sin_coefficient + sample_n1 * sin_coefficient_prev;

    // Calculate amplitude: sqrt(real^2 + imag^2) / (window_size/2)
