void ProcessProbabilityData(const std::vector<float>& probabilities, float threshold) {
    // Static variables to maintain state between calls
    static enum { INACTIVE, WAITING, RECEIVING } state = INACTIVE;
    static std::vector<int> bitBuffer;
    static std::vector<int> receivedData;

    // Predefined transmission identifiers (example patterns)
    static const std::vector<int> START_SEQUENCE = {1, 0, 1, 0, 1, 0, 1, 0};  // Example start pattern
    static const std::vector<int> END_SEQUENCE = {0, 1, 0, 1, 0, 1, 0, 1};    // Example end pattern

    // Convert probabilities to binary bits
    std::vector<int> currentBits;
    for (const float& prob : probabilities) {
        currentBits.push_back(prob >= threshold ? 1 : 0);
    }

    // Process each bit based on current state
    for (int bit : currentBits) {
        switch (state) {
            case INACTIVE:
                // Collect bits to check for start sequence
                bitBuffer.push_back(bit);
                if (bitBuffer.size() >= START_SEQUENCE.size()) {
                    // Check if we have a match with start sequence
                    bool startMatch = true;
                    for (size_t i = 0; i < START_SEQUENCE.size(); ++i) {
                        if (bitBuffer[bitBuffer.size() - START_SEQUENCE.size() + i] != START_SEQUENCE[i]) {
                            startMatch = false;
                            break;
                        }
                    }

                    if (startMatch) {
                        state = WAITING;
                        bitBuffer.clear();
                    } else {
                        // Remove oldest bit to maintain buffer size
                        if (!bitBuffer.empty()) {
                            bitBuffer.erase(bitBuffer.begin());
                        }
                    }
                }
                break;

            case WAITING:
                // Transition to receiving state and collect data
                state = RECEIVING;
                bitBuffer.push_back(bit);
                break;

            case RECEIVING:
                bitBuffer.push_back(bit);

                // Check for end sequence
                if (bitBuffer.size() >= END_SEQUENCE.size()) {
                    bool endMatch = true;
                    for (size_t i = 0; i < END_SEQUENCE.size(); ++i) {
                        if (bitBuffer[bitBuffer.size() - END_SEQUENCE.size() + i] != END_SEQUENCE[i]) {
                            endMatch = false;
                            break;
                        }
                    }

                    if (endMatch) {
                        // Extract data (excluding start and end sequences)
                        if (bitBuffer.size() > START_SEQUENCE.size() + END_SEQUENCE.size()) {
                            // Store the actual data (this is a simplified approach)
                            receivedData = bitBuffer;

                            // Optional checksum validation could be implemented here
                            // For example: validateChecksum(receivedData);

                            // Process the received data
                            processData(receivedData);
                        }

                        // Reset for next transmission
                        state = INACTIVE;
                        bitBuffer.clear();
                        receivedData.clear();
                    }
                }
                break;
        }
    }
}

