std::vector<uint8_t> ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    if (bits.empty()) {
        return std::vector<uint8_t>();
    }

    // Calculate the size of the result vector
    // If we have N bits, we need ceil(N/8) bytes
    size_t num_bytes = (bits.size() + 7) / 8;
    std::vector<uint8_t> result(num_bytes, 0);

    // Process each bit and pack into bytes
    for (size_t i = 0; i < bits.size(); ++i) {
        // Skip invalid bits (should be 0 or 1)
        if (bits[i] > 1) {
            continue;
        }

        // Determine which byte this bit belongs to
        size_t byte_index = i / 8;

        // Determine the bit position within the byte (MSB first)
        // Bit 0 in the group goes to position 7, bit 1 to position 6, etc.
        size_t bit_position = 7 - (i % 8);

        // Set the bit if the input bit is 1
        if (bits[i] == 1) {
            result[byte_index] |= (1 << bit_position);
        }
    }

    return result;
}

