void Backlight::SetBrightness(uint8_t brightness, bool save) {
    // Clamp brightness to valid range
    if (brightness > 100) {
        brightness = 100;
    }

    // Prevent redundant updates
    if (brightness == mCurrentBrightness) {
        return;
    }

    // Save the target brightness
    mTargetBrightness = brightness;

    // Save setting permanently if requested
    if (save) {
        SaveBrightnessSetting(brightness);
    }

    // If already transitioning, just update the target
    if (mIsTransitioning) {
        return;
    }

    // Start smooth transition
    mIsTransitioning = true;
    mTransitionStep = (mTargetBrightness > mCurrentBrightness) ? 1 : -1;

    // Calculate step size for smooth transition
    uint8_t diff = (mTargetBrightness > mCurrentBrightness) ? 
                   (mTargetBrightness - mCurrentBrightness) : 
                   (mCurrentBrightness - mTargetBrightness);

    // Adjust step size based on difference for smoother animation
    if (diff > 50) {
        mTransitionStep *= 4;
    } else if (diff > 20) {
        mTransitionStep *= 2;
    }

    // Start the transition timer
    StartTransitionTimer();
}

// Helper method called by timer interrupt/callback
void Backlight::UpdateTransition() {
    if (!mIsTransitioning) {
        return;
    }

    // Update current brightness
    if (mTransitionStep > 0) {
        mCurrentBrightness += mTransitionStep;
        if (mCurrentBrightness >= mTargetBrightness) {
            mCurrentBrightness = mTargetBrightness;
            mIsTransitioning = false;
        }
    } else {
        mCurrentBrightness += mTransitionStep;
        if (mCurrentBrightness <= mTargetBrightness) {
            mCurrentBrightness = mTargetBrightness;
            mIsTransitioning = false;
        }
    }

    // Apply the new brightness to hardware
    ApplyHardwareBrightness(mCurrentBrightness);

    // Stop timer if transition is complete
    if (!mIsTransitioning) {
        StopTransitionTimer();
    }
}

// Helper method to apply brightness to hardware
void Backlight::ApplyHardwareBrightness(uint8_t brightness) {
    // Convert 0-100% to hardware-specific PWM value
    uint16_t pwmValue = (brightness * mMaxPWMValue) / 100;

    // Apply to hardware (implementation depends on specific hardware)
    SetPWMOutput(pwmValue);
}

// Helper method to save brightness setting
void Backlight::SaveBrightnessSetting(uint8_t brightness) {
    // Implementation depends on storage mechanism (EEPROM, flash, etc.)
    WriteToPersistentStorage(BRIGHTNESS_SETTING_ADDR, brightness);
}

void Backlight::OnTransitionTimer()
{
    // Check if we've reached the target brightness
    if (m_currentBrightness == m_targetBrightness) {
        // Target reached, stop the transition timer
        StopTransitionTimer();
        return;
    }

    // Calculate the next brightness level
    if (m_currentBrightness < m_targetBrightness) {
        // Increase brightness towards target
        m_currentBrightness += m_transitionStep;
        // Ensure we don't overshoot the target
        if (m_currentBrightness > m_targetBrightness) {
            m_currentBrightness = m_targetBrightness;
        }
    } else {
        // Decrease brightness towards target
        m_currentBrightness -= m_transitionStep;
        // Ensure we don't undershoot the target
        if (m_currentBrightness < m_targetBrightness) {
            m_currentBrightness = m_targetBrightness;
        }
    }

    // Apply the new brightness level to hardware
    SetHardwareBrightness(m_currentBrightness);

    // Check again if we've reached the target after adjustment
    if (m_currentBrightness == m_targetBrightness) {
        // Target reached, stop the transition timer
        StopTransitionTimer();
    }
}

PwmBacklight::PwmBacklight(gpio_num_t gpio_pin, bool inverted, uint32_t frequency_hz) {
    // Configure LEDC timer
    ledc_timer_config_t timer_conf = {};
    timer_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    timer_conf.timer_num = LEDC_TIMER_0;
    timer_conf.duty_resolution = LEDC_TIMER_10_BIT;  // 10-bit resolution (0-1023)
    timer_conf.freq_hz = frequency_hz;
    timer_conf.clk_cfg = LEDC_AUTO_CLK;

    ledc_timer_config(&timer_conf);

    // Configure LEDC channel
    ledc_channel_config_t channel_conf = {};
    channel_conf.gpio_num = gpio_pin;
    channel_conf.speed_mode = LEDC_LOW_SPEED_MODE;
    channel_conf.channel = LEDC_CHANNEL_0;
    channel_conf.intr_type = LEDC_INTR_DISABLE;
    channel_conf.timer_sel = LEDC_TIMER_0;
    channel_conf.duty = 0;  // Start with 0% duty cycle (off)
    channel_conf.hpoint = 0;

    // Apply inversion if requested
    if (inverted) {
        channel_conf.flags.output_invert = 1;
    } else {
        channel_conf.flags.output_invert = 0;
    }

    ledc_channel_config(&channel_conf);

    // Store member variables
    this->gpio_pin_ = gpio_pin;
    this->inverted_ = inverted;
    this->frequency_hz_ = frequency_hz;
    this->channel_ = LEDC_CHANNEL_0;
    this->timer_ = LEDC_TIMER_0;

    // Initialize to 0% brightness
    set_brightness(0);
}

void PwmBacklight::SetBrightnessImpl(uint8_t brightness_percent) {
    // Cap the brightness at 100% to prevent overflow
    if (brightness_percent > 100) {
        brightness_percent = 100;
    }

    // Map brightness percentage (0-100) to 10-bit PWM range (0-1023)
    // Using integer arithmetic to avoid floating point operations
    uint32_t duty_cycle = (static_cast<uint32_t>(brightness_percent) * 1023) / 100;

    // Update the LEDC channel with the new duty cycle
    // Assuming LEDC_CHANNEL_0 and ledc_set_duty_and_update() function
    ledc_set_duty_and_update(LEDC_LOW_SPEED_MODE, LEDC_CHANNEL_0, duty_cycle, 0);
}

