std::string Board::GenerateUuid() {
    uint8_t uuid[16];

    // Generate 16 random bytes using ESP32 hardware RNG
    for (int i = 0; i < 16; i++) {
        uuid[i] = esp_random() & 0xFF;
    }

    // Set UUID version to 4 (random) - bits 12-15 of byte 6 should be 0100
    uuid[6] = (uuid[6] & 0x0F) | 0x40;

    // Set UUID variant to RFC 4122 - bits 6-7 of byte 8 should be 10
    uuid[8] = (uuid[8] & 0x3F) | 0x80;

    // Format as hexadecimal string with hyphens
    char uuid_str[37]; // 36 chars + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

