Button::Button(gpio_num_t gpio_pin, bool active_high, uint16_t short_press_ms, uint16_t long_press_ms, bool power_save_enabled)
{
    // Store configuration parameters
    this->gpio_pin = gpio_pin;
    this->active_high = active_high;
    this->short_press_threshold = short_press_ms;
    this->long_press_threshold = long_press_ms;
    this->power_save_mode = power_save_enabled;

    // Initialize state variables
    this->button_state = BUTTON_RELEASED;
    this->press_start_time = 0;
    this->last_debounce_time = 0;
    this->debounce_delay = 50; // 50ms debounce default

    // Configure GPIO pin
    gpio_config_t io_conf;
    io_conf.intr_type = GPIO_INTR_ANYEDGE; // Interrupt on both edges
    io_conf.mode = GPIO_MODE_INPUT;
    io_conf.pin_bit_mask = (1ULL << gpio_pin);
    io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
    io_conf.pull_up_en = active_high ? GPIO_PULLUP_ENABLE : GPIO_PULLUP_DISABLE;

    // Apply GPIO configuration
    gpio_config(&io_conf);

    // Install GPIO ISR service if not already installed
    static bool isr_service_installed = false;
    if (!isr_service_installed) {
        gpio_install_isr_service(ESP_INTR_FLAG_LEVEL3);
        isr_service_installed = true;
    }

    // Add ISR handler for this button
    gpio_isr_handler_add(gpio_pin, button_isr_handler, this);

    // Initialize timer for periodic checking if power save is enabled
    if (power_save_enabled) {
        // Configure timer for low-power periodic polling
        esp_timer_create_args_t timer_args = {
            .callback = &button_timer_callback,
            .arg = this,
            .dispatch_method = ESP_TIMER_TASK,
            .name = "button_timer"
        };
        esp_timer_create(&timer_args, &this->button_timer);
    }

    // Register with input handling framework
    input_manager_register_button(this);

    // Initialize button event queue
    this->event_queue = xQueueCreate(10, sizeof(button_event_t));

    // Start button monitoring task
    xTaskCreate(button_monitor_task, "button_task", 2048, this, 10, &this->button_task_handle);
}

