void Button::OnClick(std::function<void()> callback)
{
    // Validate that the button handle is valid before setting the click handler
    if (m_buttonHandle == nullptr)
    {
        // Handle invalid button handle case
        return;
    }

    // Store the callback function for later use
    m_clickCallback = std::move(callback);

    // Register the callback with the IoT button library
    // Using a lambda or wrapper function to bridge between C++ std::function and C-style callback
    auto callbackWrapper = [](void* context) -> void {
        Button* buttonInstance = static_cast<Button*>(context);
        if (buttonInstance && buttonInstance->m_clickCallback)
        {
            buttonInstance->m_clickCallback();
        }
    };

    // Register the callback with the IoT button library using the button handle and context
    iot_button_register_callback(m_buttonHandle, BUTTON_CLICK_EVENT, callbackWrapper, this);
}

void Button::OnDoubleClick(std::function<void()> callback) {
    // Check if the button handle is valid before registering the callback
    if (handle_ == nullptr || handle_ == INVALID_HANDLE_VALUE) {
        return; // Early return if handle is invalid
    }

    // Store the callback for later execution
    double_click_callback_ = std::move(callback);

    // Register the double-click event handler with the underlying system
    // This typically involves setting up a message handler or event listener
    if (!is_double_click_handler_registered_) {
        // Register the actual double-click event detection mechanism
        // This could involve calling OS-specific APIs or framework functions
        RegisterEventHandler(ButtonEvent::DOUBLE_CLICK, [this]() {
            // When double-click event is detected, invoke the stored callback
            if (double_click_callback_) {
                double_click_callback_();
            }
        });

        is_double_click_handler_registered_ = true;
    }
}

void Button::OnMultipleClick(std::function<void()> callback, uint8_t clickCount)
{
    // Store the callback function and required click count
    this->multipleClickCallback = callback;
    this->requiredClickCount = clickCount;

    // Initialize click tracking variables
    this->currentClickCount = 0;
    this->lastClickTime = 0;

    // Set up the button event handler for click detection
    this->onClick([this]() {
        // Get current time (assuming millis() or similar time function exists)
        uint32_t currentTime = getCurrentTimeMs();

        // Check if this is part of a multi-click sequence (within timeout)
        if (currentTime - this->lastClickTime <= CLICK_TIMEOUT_MS) {
            // Increment click counter
            this->currentClickCount++;
        } else {
            // Reset counter for new sequence
            this->currentClickCount = 1;
        }

        // Update last click time
        this->lastClickTime = currentTime;

        // Check if we've reached the required number of clicks
        if (this->currentClickCount == this->requiredClickCount) {
            // Execute the registered callback
            if (this->multipleClickCallback) {
                this->multipleClickCallback();
            }

            // Reset counter after successful multi-click
            this->currentClickCount = 0;
        }
    });
}

