void WriteReg(uint8_t regAddr, uint8_t value) {
    // Create a 2-byte buffer: [register_address, value]
    uint8_t buffer[2];
    buffer[0] = regAddr;
    buffer[1] = value;

    // Transmit the buffer to the I2C device using master interface
    // Assuming there's an I2C master object (e.g., i2cMaster) with a write method
    // and a predefined device address (e.g., I2C_DEVICE_ADDR)
    i2cMaster.write(I2C_DEVICE_ADDR, buffer, 2, 100);
}

uint8_t ReadReg(uint8_t regAddr) {
    uint8_t data = 0;

    // Start I2C communication with device write address
    I2C_Start();
    I2C_Write((deviceAddress << 1) | 0); // Write mode

    // Send register address
    I2C_Write(regAddr);

    // Restart with device read address
    I2C_Start();
    I2C_Write((deviceAddress << 1) | 1); // Read mode

    // Read data byte (with NACK since it's single byte)
    data = I2C_Read(0); // 0 = NACK for last byte

    // Stop I2C communication
    I2C_Stop();

    return data;
}

WifiBoard::WifiBoard() 
{
    // Initialize the connection timeout timer
    connectionTimeoutTimer = new Timer();

    // Set default timeout duration (e.g., 30 seconds)
    timeoutDuration = 30000; // 30 seconds in milliseconds

    // Configure the timer with callback function for timeout events
    connectionTimeoutTimer->setCallback([this]() {
        this->handleConnectionTimeout();
    });

    // Initialize WiFi module/components
    wifiInitialized = false;
    connectionAttemptActive = false;

    // Set initial state
    connectionStatus = WIFI_DISCONNECTED;

    // Initialize any other necessary members
    maxConnectionAttempts = 3;
    currentAttempt = 0;
}

// Additional helper function that would be called on timeout
void WifiBoard::handleConnectionTimeout() 
{
    // Stop the current connection attempt
    connectionAttemptActive = false;

    // Increment attempt counter
    currentAttempt++;

    // Check if we should retry or give up
    if (currentAttempt < maxConnectionAttempts) {
        // Retry connection
        reconnect();
    } else {
        // Give up and report failure
        connectionStatus = WIFI_CONNECTION_FAILED;
        // Notify upper layers of connection failure
        notifyConnectionFailure();
    }
}

~WifiBoard() {
    // Stop the WiFi connection timer to prevent any ongoing operations
    if (wifiTimer != nullptr) {
        wifiTimer->stop();
        delete wifiTimer;
        wifiTimer = nullptr;
    }
}

