int WifiBoard::GetNetworkStateIcon() {
    // Check if device is in configuration mode
    if (IsInConfigurationMode()) {
        return ICON_WIFI_CONFIG;  // Configuration mode icon
    }

    // Check connection status
    if (!IsConnected()) {
        return ICON_WIFI_DISCONNECTED;  // Disconnected/empty icon
    }

    // Device is connected, check signal strength
    int signalStrength = GetSignalStrength();

    // Determine icon based on signal strength thresholds
    if (signalStrength >= SIGNAL_STRONG_THRESHOLD) {
        return ICON_WIFI_STRONG;     // Strong signal - full bars
    } else if (signalStrength >= SIGNAL_FAIR_THRESHOLD) {
        return ICON_WIFI_FAIR;       // Fair signal - medium bars
    } else {
        return ICON_WIFI_WEAK;       // Weak signal - low bars
    }
}

std::string WifiBoard::GetBoardJson() {
    Json::Value root;

    // Add basic board information (always present)
    root["type"] = GetBoardType();
    root["name"] = GetBoardName();
    root["mac"] = GetMacAddress();

    // Add Wi-Fi information only when not in configuration mode
    if (!IsInConfigMode()) {
        Json::Value wifiInfo;

        // Get Wi-Fi connection details
        std::string ssid = GetConnectedSSID();
        if (!ssid.empty()) {
            wifiInfo["ssid"] = ssid;
        }

        int rssi = GetRSSI();
        if (rssi != 0) {  // Assuming 0 means not connected or invalid
            wifiInfo["rssi"] = rssi;
        }

        int channel = GetChannel();
        if (channel > 0) {
            wifiInfo["channel"] = channel;
        }

        std::string ipAddress = GetIPAddress();
        if (!ipAddress.empty()) {
            wifiInfo["ip"] = ipAddress;
        }

        // Only add wifi object if we have some wifi information
        if (!wifiInfo.empty()) {
            root["wifi"] = wifiInfo;
        }
    }

    // Convert to JSON string
    Json::StreamWriterBuilder builder;
    builder["indentation"] = "";  // Compact format
    return Json::writeString(builder, root);
}

void SetPowerSaveLevel(PowerSaveLevel level) {
    // Map general power save levels to Wi-Fi specific levels
    WiFiPowerSaveLevel wifiLevel;

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            wifiLevel = WiFiPowerSaveLevel::WIFI_PS_MIN_MODEM;
            break;
        case PowerSaveLevel::BALANCED:
            wifiLevel = WiFiPowerSaveLevel::WIFI_PS_MAX_MODEM;
            break;
        case PowerSaveLevel::PERFORMANCE:
            wifiLevel = WiFiPowerSaveLevel::WIFI_PS_NONE;
            break;
        default:
            // Handle invalid power save level
            return;
    }

    // Get Wi-Fi manager instance and apply the power save setting
    WiFiManager& wifiManager = WiFiManager::GetInstance();
    wifiManager.SetPowerSaveMode(wifiLevel);
}

