// Global variables to maintain LED state
static rmt_channel_t rmt_channel = RMT_CHANNEL_0;
static gpio_num_t led_gpio_pin;
static TimerHandle_t blink_timer = NULL;

// WS2812 timing constants (in nanoseconds)
#define T0H 400   // 0 bit high time
#define T0L 850   // 0 bit low time  
#define T1H 800   // 1 bit high time
#define T1L 450   // 1 bit low time
#define RESET_TIME 50000  // Reset time in nanoseconds

// Function to send RGB color data via RMT
static void ws2812_write_led(uint32_t red, uint32_t green, uint32_t blue) {
    rmt_item32_t items[24];  // 24 bits for RGB

    uint32_t color = (green << 16) | (red << 8) | blue;  // GRB format for WS2812

    for (int i = 0; i < 24; i++) {
        if (color & (1 << (23 - i))) {
            // Bit 1
            items[i].level0 = 1;
            items[i].duration0 = T1H / 12.5;  // Convert to RMT ticks (assuming 80MHz clock)
            items[i].level1 = 0;
            items[i].duration1 = T1L / 12.5;
        } else {
            // Bit 0
            items[i].level0 = 1;
            items[i].duration0 = T0H / 12.5;
            items[i].level1 = 0;
            items[i].duration1 = T0L / 12.5;
        }
    }

    rmt_write_items(rmt_channel, items, 24, true);
}

// Timer callback for blinking
static void blink_timer_callback(TimerHandle_t xTimer) {
    // This will be implemented based on specific blink requirements
    // For now, just clear the LED to demonstrate the timer working
    ws2812_write_led(0, 0, 0);
}

void SingleLed(gpio_num_t gpio_pin) {
    // Store the GPIO pin for future use
    led_gpio_pin = gpio_pin;

    // Configure GPIO
    gpio_config_t io_conf = {};
    io_conf.intr_type = GPIO_INTR_DISABLE;
    io_conf.mode = GPIO_MODE_OUTPUT;
    io_conf.pin_bit_mask = (1ULL << gpio_pin);
    io_conf.pull_down_en = GPIO_PULLDOWN_DISABLE;
    io_conf.pull_up_en = GPIO_PULLUP_DISABLE;
    gpio_config(&io_conf);

    // Configure RMT peripheral
    rmt_config_t rmt_cfg = {};
    rmt_cfg.channel = rmt_channel;
    rmt_cfg.gpio_num = gpio_pin;
    rmt_cfg.clk_div = 2;  // 80MHz / 2 = 40MHz, each tick = 25ns
    rmt_cfg.mem_block_num = 1;
    rmt_cfg.tx_config.loop_en = false;
    rmt_cfg.tx_config.carrier_en = false;
    rmt_cfg.tx_config.idle_level = 0;
    rmt_cfg.tx_config.idle_output_en = true;
    rmt_cfg.rmt_mode = RMT_MODE_TX;
    rmt_config(&rmt_cfg);
    rmt_driver_install(rmt_channel, 0, 0);

    // Clear the LED (turn off)
    ws2812_write_led(0, 0, 0);

    // Create blinking timer (1 second interval, auto-reload)
    blink_timer = xTimerCreate(
        "LED_Blink_Timer",
        pdMS_TO_TICKS(1000),  // 1 second period
        pdTRUE,               // Auto-reload
        (void*)0,             // Timer ID
        blink_timer_callback  // Callback function
    );

    // Start the timer if created successfully
    if (blink_timer != NULL) {
        xTimerStart(blink_timer, 0);
    }
}

~SingleLed() {
    // Stop the LED blink timer to prevent further callbacks
    if (blinkTimer != nullptr) {
        blinkTimer->stop();
        delete blinkTimer;
        blinkTimer = nullptr;
    }

    // Safely deallocate the LED strip resource if it exists
    if (ledStrip != nullptr) {
        // Turn off the LED before deallocation
        ledStrip->setPixelColor(0, 0, 0, 0);
        ledStrip->show();

        // Delete the LED strip object
        delete ledStrip;
        ledStrip = nullptr;
    }
}

