void SingleLed::TurnOn()
{
    // Acquire mutex for thread-safe operation
    std::lock_guard<std::mutex> lock(ledMutex);

    // Stop any ongoing blink timer
    if (blinkTimer) {
        blinkTimer->stop();
    }

    // Set the LED color to configured RGB values
    ledStrip.setPixelColor(ledIndex, rgbConfig.red, rgbConfig.green, rgbConfig.blue);

    // Immediately refresh the LED strip to display the change
    ledStrip.show();
}

void SingleLed::TurnOff() {
    // Acquire mutex lock for thread-safe execution
    std::lock_guard<std::mutex> lock(m_mutex);

    // Null check to prevent errors if LED strip is uninitialized
    if (m_ledStrip == nullptr) {
        return;
    }

    // Stop any active blinking timer
    if (m_blinkTimer != nullptr) {
        m_blinkTimer->Stop();
    }

    // Clear the LED strip state (turn off the LED)
    m_ledStrip->Clear();

    // Reset any blinking state variables
    m_isBlinking = false;
    m_blinkState = false;
}

void StartBlinkTask(int numBlinks, int intervalMs)
{
    // Check if LED strip is initialized, exit early if not
    if (!isLedStripInitialized()) {
        return;
    }

    // Validate input parameters
    if (numBlinks <= 0 || intervalMs <= 0) {
        return;
    }

    // Set the blinking parameters
    blinkCount = 0;
    totalBlinks = numBlinks;
    blinkInterval = intervalMs;

    // Reset LED state
    currentLedState = LED_OFF;
    setLedState(currentLedState);

    // Configure and start the periodic timer
    configureTimer(blinkInterval);
    startTimer();
}

void SingleLed::OnBlinkTimer()
{
    // Acquire mutex for thread-safe access to LED state
    std::lock_guard<std::mutex> lock(m_mutex);

    // Decrement the blink counter
    if (m_blinkCount > 0)
    {
        m_blinkCount--;

        // Toggle the LED state
        if (m_state == LedState::ON)
        {
            m_state = LedState::OFF;
            // Turn off the physical LED
            SetHardwareLed(false);
        }
        else
        {
            m_state = LedState::ON;
            // Turn on the physical LED
            SetHardwareLed(true);
        }

        // If this was the last blink, stop the timer
        if (m_blinkCount == 0)
        {
            StopTimer();
        }
    }
    else
    {
        // Blink count is already zero, stop the timer
        StopTimer();
    }
}

void SingleLed::OnStateChanged()
{
    // Stop any ongoing LED animations first
    StopAnimation();

    switch (m_currentState)
    {
        case DeviceState::STARTING:
            // Blue solid light during startup
            SetColor(LED_COLOR_BLUE);
            SetBlinkPattern(BlinkPattern::SOLID);
            break;

        case DeviceState::WIFI_CONFIG:
            // Yellow blinking to indicate configuration mode
            SetColor(LED_COLOR_YELLOW);
            SetBlinkPattern(BlinkPattern::SLOW_BLINK);
            break;

        case DeviceState::IDLE:
            // Green solid when ready and idle
            SetColor(LED_COLOR_GREEN);
            SetBlinkPattern(BlinkPattern::SOLID);
            break;

        case DeviceState::CONNECTING:
            // Blue fast blinking during connection attempts
            SetColor(LED_COLOR_BLUE);
            SetBlinkPattern(BlinkPattern::FAST_BLINK);
            break;

        case DeviceState::LISTENING:
            // Purple pulsing for audio listening mode
            SetColor(LED_COLOR_PURPLE);
            SetBlinkPattern(BlinkPattern::PULSE);
            break;

        case DeviceState::SPEAKING:
            // White pulsing for audio output
            SetColor(LED_COLOR_WHITE);
            SetBlinkPattern(BlinkPattern::PULSE);
            break;

        case DeviceState::UPGRADING:
            // Orange fast blinking during firmware upgrade
            SetColor(LED_COLOR_ORANGE);
            SetBlinkPattern(BlinkPattern::FAST_BLINK);
            break;

        case DeviceState::ACTIVATING:
            // Rainbow cycling effect during activation
            SetBlinkPattern(BlinkPattern::RAINBOW_CYCLE);
            break;

        default:
            // Unknown state - turn off LED for safety
            SetColor(LED_COLOR_OFF);
            SetBlinkPattern(BlinkPattern::SOLID);
            break;
    }

    // Apply the new LED settings
    ApplyChanges();
}

MqttProtocol::MqttProtocol()
{
    // Initialize the event group for MQTT synchronization
    m_mqttEventGroup = xEventGroupCreate();
    if (m_mqttEventGroup == NULL) {
        // Handle event group creation failure
        // Log error or set error flag
        return;
    }

    // Initialize event bits for different MQTT states
    // Common pattern: CONNECTED, DISCONNECTED, RECONNECTING, ERROR
    xEventGroupClearBits(m_mqttEventGroup, 
                        MQTT_CONNECTED_BIT | 
                        MQTT_DISCONNECTED_BIT | 
                        MQTT_RECONNECTING_BIT | 
                        MQTT_ERROR_BIT);

    // Create reconnect timer - this will be used for periodic reconnection attempts
    m_reconnectTimer = xTimerCreate(
        "MqttReconnectTimer",           // Timer name
        pdMS_TO_TICKS(MQTT_RECONNECT_INTERVAL_MS), // Timer period (convert ms to ticks)
        pdTRUE,                         // Auto-reload (periodic timer)
        this,                          // Timer ID (pass this object reference)
        MqttReconnectTimerCallback     // Callback function
    );

    if (m_reconnectTimer == NULL) {
        // Handle timer creation failure
        vEventGroupDelete(m_mqttEventGroup);
        m_mqttEventGroup = NULL;
        return;
    }

    // Initialize MQTT client configuration
    m_mqttClientConfig = {0};
    m_mqttClientConfig.transport = MQTT_TRANSPORT_OVER_TCP;
    m_mqttClientConfig.networkTimeoutMs = MQTT_NETWORK_TIMEOUT_MS;
    m_mqttClientConfig.pingTimeoutMs = MQTT_PING_TIMEOUT_MS;

    // Set initial state
    m_connectionState = MQTT_STATE_DISCONNECTED;
    m_reconnectAttempts = 0;

    // Mark that the MQTT protocol layer is initialized
    m_initialized = true;

    // Note: Actual connection will be initiated separately based on application logic
    // This constructor only sets up the infrastructure for MQTT communication
}

// Static callback function for the reconnect timer
void MqttProtocol::MqttReconnectTimerCallback(TimerHandle_t xTimer)
{
    // Retrieve the MqttProtocol instance from timer ID
    MqttProtocol* mqttProtocol = static_cast<MqttProtocol*>(pvTimerGetTimerID(xTimer));

    if (mqttProtocol != nullptr) {
        // Check if device is in idle state before attempting reconnection
        if (mqttProtocol->IsDeviceInIdleState()) {
            // Schedule reconnection through task scheduler to avoid blocking timer context
            BaseType_t xHigherPriorityTaskWoken = pdFALSE;

            // Attempt to send reconnection request to MQTT task
            if (mqttProtocol->m_mqttTaskHandle != NULL) {
                // Send message to MQTT task to handle reconnection
                MQTT_TaskMessage msg;
                msg.type = MQTT_MSG_RECONNECT;
                msg.data = nullptr;

                // Use appropriate queue/communication mechanism
                xQueueSendFromISR(mqttProtocol->m_mqttMessageQueue, &msg, &xHigherPriorityTaskWoken);

                portYIELD_FROM_ISR(xHigherPriorityTaskWoken);
            }
        }
        // If not in idle state, wait for next timer cycle
    }
}

