MqttProtocol::~MqttProtocol()
{
    // Mark instance as inactive first to prevent any new operations
    isActive = false;

    // Stop and delete the reconnect timer to prevent future reconnection attempts
    if (reconnectTimer != nullptr) {
        // Stop the timer first
        xTimerStop(reconnectTimer, 0);
        // Delete the timer to free its resources
        xTimerDelete(reconnectTimer, 0);
        reconnectTimer = nullptr;
    }

    // Reset UDP resources - close socket connections and clean up network resources
    if (udpSocket != -1) {
        close(udpSocket);
        udpSocket = -1;
    }

    // Reset MQTT resources - clear buffers, reset state variables
    if (mqttBuffer != nullptr) {
        delete[] mqttBuffer;
        mqttBuffer = nullptr;
    }

    // Reset MQTT connection state
    mqttState = MQTT_STATE_DISCONNECTED;
    connectionAttempts = 0;

    // Release the associated event group used for synchronization
    if (mqttEventGroup != nullptr) {
        vEventGroupDelete(mqttEventGroup);
        mqttEventGroup = nullptr;
    }

    // Clear any remaining message queues or callbacks
    if (messageQueue != nullptr) {
        // Flush and delete message queue
        while (!messageQueue->empty()) {
            MqttMessage* msg = messageQueue->front();
            messageQueue->pop();
            delete msg;
        }
        delete messageQueue;
        messageQueue = nullptr;
    }
}

void StartMqttClient(bool forceReconnect) {
    // Load MQTT configuration
    MqttConfig config = LoadMqttConfiguration();

    // Check if client is already running and handle accordingly
    if (mqttClient.IsConnected() && !forceReconnect) {
        return; // Already connected, no need to restart
    }

    // Disconnect existing client if connected and force reconnect is requested
    if (mqttClient.IsConnected() && forceReconnect) {
        mqttClient.Disconnect();
        // Wait for clean disconnect
        Thread::Sleep(100);
    }

    try {
        // Initialize MQTT client with configuration
        mqttClient.SetBrokerAddress(config.brokerHost);
        mqttClient.SetBrokerPort(config.brokerPort);
        mqttClient.SetClientId(config.clientId);
        mqttClient.SetCredentials(config.username, config.password);
        mqttClient.SetKeepAliveInterval(config.keepAliveSeconds);
        mqttClient.SetCleanSession(config.cleanSession);

        // Setup event handlers
        mqttClient.OnConnect([this]() {
            LogInfo("MQTT Client Connected Successfully");
            isConnected = true;
            cancelReconnectTimer(); // Cancel any pending reconnect attempts

            // Subscribe to relevant topics
            SubscribeToTopics();

            // Notify system of successful connection
            OnMqttConnected();
        });

        mqttClient.OnDisconnect([this](ConnectionReason reason) {
            LogWarning("MQTT Client Disconnected. Reason: " + std::to_string(static_cast<int>(reason)));
            isConnected = false;

            // Trigger session cleanup
            HandleSessionDisconnection();

            // Schedule reconnect attempt
            ScheduleReconnect();
        });

        mqttClient.OnMessage([this](const std::string& topic, const std::vector<uint8_t>& payload) {
            try {
                // Parse JSON payload
                std::string payloadStr(payload.begin(), payload.end());
                Json::Value jsonPayload = ParseJson(payloadStr);

                // Route message based on topic
                if (topic == config.audioControlTopic) {
                    HandleAudioChannelControl(jsonPayload);
                } else if (topic == config.sessionManagementTopic) {
                    HandleSessionManagement(jsonPayload);
                } else {
                    HandleGenericMessage(topic, jsonPayload);
                }
            } catch (const std::exception& e) {
                LogError("Failed to parse/process MQTT message: " + std::string(e.what()));
            }
        });

        // Attempt connection
        LogInfo("Attempting to connect to MQTT broker: " + config.brokerHost + ":" + std::to_string(config.brokerPort));
        ConnectionResult result = mqttClient.Connect();

        if (result != ConnectionResult::SUCCESS) {
            LogError("Failed to connect to MQTT broker. Result: " + std::to_string(static_cast<int>(result)));
            isConnected = false;
            ScheduleReconnect();
            return;
        }

        LogInfo("MQTT client started successfully");

    } catch (const std::exception& e) {
        LogError("Exception during MQTT client startup: " + std::string(e.what()));
        isConnected = false;
        ScheduleReconnect();
    }
}

