private:
    void SubscribeToTopics() {
        MqttConfig config = LoadMqttConfiguration();
        mqttClient.Subscribe(config.audioControlTopic, QoS::AT_LEAST_ONCE);
        mqttClient.Subscribe(config.sessionManagementTopic, QoS::AT_LEAST_ONCE);
        // Subscribe to additional topics as needed
    }

    void ScheduleReconnect() {
        MqttConfig config = LoadMqttConfiguration();
        reconnectTimer.Start(config.reconnectIntervalMs, [this]() {
            LogInfo("Attempting MQTT reconnect...");
            StartMqttClient(true); // Force reconnect
        });
    }

    void cancelReconnectTimer() {
        reconnectTimer.Cancel();
    }

    void HandleAudioChannelControl(const Json::Value& payload) {
        // Extract audio control commands and execute them
        if (payload.isMember("channel") && payload.isMember("action")) {
            std::string channel = payload["channel"].asString();
            std::string action = payload["action"].asString();

            if (action == "enable") {
                EnableAudioChannel(channel);
            } else if (action == "disable") {
                DisableAudioChannel(channel);
            } else if (action == "volume") {
                int volume = payload["volume"].asInt();
                SetAudioChannelVolume(channel, volume);
            }
        }
    }

    void HandleSessionManagement(const Json::Value& payload) {
        if (payload.isMember("sessionId") && payload.isMember("command")) {
            std::string sessionId = payload["sessionId"].asString();
            std::string command = payload["command"].asString();

            if (command == "start") {
                StartSession(sessionId);
            } else if (command == "end") {
                EndSession(sessionId);
            } else if (command == "pause") {
                PauseSession(sessionId);
            }
        }
    }

    void HandleSessionDisconnection() {
        // Clean up active sessions on disconnection
        TerminateActiveSessions();
    }

bool SendText(const std::string& message) {
    // Predefined MQTT topic for text messages
    static const std::string TEXT_TOPIC = "system/messages/text";

    // Attempt to publish the message to the MQTT topic
    bool publishSuccess = false;

    // Assuming there's an MQTT client instance available
    // This could be a global variable or member variable
    if (mqttClient.isConnected()) {
        // Publish with QoS level 1 for at least once delivery
        publishSuccess = mqttClient.publish(TEXT_TOPIC, message, 1);
    } else {
        // Log error if MQTT client is not connected
        LOG_ERROR("MQTT client not connected. Cannot send text message: %s", message.c_str());
        SetServerError(ErrorCode::MQTT_DISCONNECTED);
        return false;
    }

    // Check if publishing was successful
    if (publishSuccess) {
        // Optional: Log successful transmission
        LOG_DEBUG("Successfully sent text message to topic %s", TEXT_TOPIC.c_str());
        return true;
    } else {
        // Log error, set server error state, and return false
        LOG_ERROR("Failed to publish text message to topic %s: %s", TEXT_TOPIC.c_str(), message.c_str());
        SetServerError(ErrorCode::MQTT_PUBLISH_FAILED);
        return false;
    }
}

bool SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    if (!packet || !packet->data || packet->size == 0) {
        return false;
    }

    // Thread-safe access to shared resources
    std::lock_guard<std::mutex> lock(udp_channel_mutex);

    try {
        // Generate timestamp
        auto timestamp = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now().time_since_epoch()).count();

        // Create nonce with packet size, timestamp, and sequence number
        uint8_t nonce[AES_BLOCK_SIZE] = {0};
        memcpy(nonce, &packet->size, sizeof(packet->size));
        memcpy(nonce + sizeof(packet->size), &timestamp, sizeof(timestamp));
        uint32_t seq_num = htonl(sequence_number++);
        memcpy(nonce + sizeof(packet->size) + sizeof(timestamp), &seq_num, sizeof(seq_num));

        // Prepare encryption
        AES_KEY aes_key;
        if (AES_set_encrypt_key(encryption_key.data(), 128, &aes_key) != 0) {
            return false;
        }

        // Allocate buffer for encrypted data
        std::vector<uint8_t> encrypted_data(packet->size);
        uint8_t counter[AES_BLOCK_SIZE] = {0};
        uint8_t keystream[AES_BLOCK_SIZE];
        unsigned int num = 0;

        // Copy nonce to counter
        memcpy(counter, nonce, AES_BLOCK_SIZE);

        // Perform AES-CTR encryption
        AES_ctr128_encrypt(
            static_cast<const uint8_t*>(packet->data.get()), 
            encrypted_data.data(), 
            packet->size, 
            &aes_key, 
            counter, 
            keystream, 
            &num
        );

        // Prepare UDP packet header with metadata
        AudioPacketHeader header;
        header.packet_size = htonl(packet->size);
        header.timestamp = htonll(timestamp);
        header.sequence_number = htonl(sequence_number - 1);
        memcpy(header.nonce, nonce, sizeof(header.nonce));

        // Create final packet (header + encrypted data)
        std::vector<uint8_t> udp_packet(sizeof(AudioPacketHeader) + packet->size);
        memcpy(udp_packet.data(), &header, sizeof(AudioPacketHeader));
        memcpy(udp_packet.data() + sizeof(AudioPacketHeader), encrypted_data.data(), packet->size);

        // Transmit over UDP
        int bytes_sent = sendto(
            udp_socket_fd,
            udp_packet.data(),
            udp_packet.size(),
            0,
            reinterpret_cast<struct sockaddr*>(&destination_addr),
            sizeof(destination_addr)
        );

        // Check if all bytes were sent
        if (bytes_sent != static_cast<int>(udp_packet.size())) {
            return false;
        }

        return true;
    }
    catch (const std::exception& e) {
        // Log error if logging is available
        return false;
    }
}

void CloseAudioChannel()
{
    // Send goodbye message to server before closing connection
    const char* goodbyeMessage = "GOODBYE";
    int messageLength = strlen(goodbyeMessage);

    // Send the goodbye message via UDP
    int bytesSent = sendto(udpSocket, goodbyeMessage, messageLength, 0, 
                          (struct sockaddr*)&serverAddress, sizeof(serverAddress));

    // Reset UDP connection (close and invalidate socket)
    if (udpSocket >= 0) {
        close(udpSocket);
        udpSocket = -1;
    }

    // Clear any remaining audio buffers or streaming state
    memset(&audioBuffer, 0, sizeof(audioBuffer));
    isStreaming = false;

    // Trigger callback notification to inform application
    if (audioChannelClosedCallback != nullptr) {
        audioChannelClosedCallback();
    }
}

bool MqttProtocol::OpenAudioChannel() {
    try {
        // Step 1: Connect to MQTT server
        if (!mqttClient.connect(mqttBrokerUrl, mqttPort, mqttUsername, mqttPassword)) {
            LOG_ERROR("Failed to connect to MQTT broker");
            return false;
        }

        // Step 2: Subscribe to control channel for handshake
        std::string controlTopic = "audio/control/" + clientId;
        if (!mqttClient.subscribe(controlTopic, [this](const std::string& topic, const std::string& payload) {
            this->handleControlMessage(topic, payload);
        })) {
            LOG_ERROR("Failed to subscribe to control topic");
            mqttClient.disconnect();
            return false;
        }

        // Step 3: Send hello message
        std::string helloTopic = "audio/hello";
        nlohmann::json helloMsg;
        helloMsg["clientId"] = clientId;
        helloMsg["timestamp"] = getCurrentTimestamp();
        helloMsg["protocolVersion"] = PROTOCOL_VERSION;

        if (!mqttClient.publish(helloTopic, helloMsg.dump())) {
            LOG_ERROR("Failed to send hello message");
            mqttClient.unsubscribe(controlTopic);
            mqttClient.disconnect();
            return false;
        }

        // Step 4: Wait for server response with timeout
        std::unique_lock<std::mutex> lock(handshakeMutex);
        if (!handshakeCondition.wait_for(lock, std::chrono::seconds(HANDSHAKE_TIMEOUT), 
                                         [this]() { return handshakeCompleted; })) {
            LOG_ERROR("Handshake timeout");
            mqttClient.unsubscribe(controlTopic);
            mqttClient.disconnect();
            return false;
        }

        if (!handshakeSuccess) {
            LOG_ERROR("Handshake failed");
            mqttClient.unsubscribe(controlTopic);
            mqttClient.disconnect();
            return false;
        }

        // Step 5: Extract connection parameters from handshake response
        std::string udpHost = serverUdpHost;
        int udpPort = serverUdpPort;
        std::string sessionKey = serverSessionKey;

        // Step 6: Setup UDP connection for audio packets
        udpSocket = std::make_unique<UDPSocket>();
        if (!udpSocket->bind(LOCAL_UDP_PORT)) {
            LOG_ERROR("Failed to bind UDP socket");
            mqttClient.unsubscribe(controlTopic);
            mqttClient.disconnect();
            return false;
        }

        if (!udpSocket->connect(udpHost, udpPort)) {
            LOG_ERROR("Failed to connect UDP socket to server");
            udpSocket->close();
            mqttClient.unsubscribe(controlTopic);
            mqttClient.disconnect();
            return false;
        }

        // Step 7: Start audio reception thread
        audioReceptionThread = std::thread([this, sessionKey]() {
            this->receiveAudioPackets(sessionKey);
        });

        // Step 8: Update channel state
        isAudioChannelOpen = true;
        lastPacketTime = std::chrono::steady_clock::now();

        LOG_INFO("Audio channel opened successfully");
        return true;

    } catch (const std::exception& e) {
        LOG_ERROR("Exception in OpenAudioChannel: %s", e.what());
        cleanupAudioChannel();
        return false;
    }
}

private:
void MqttProtocol::handleControlMessage(const std::string& topic, const std::string& payload) {
    try {
        auto msg = nlohmann::json::parse(payload);
        std::string msgType = msg.value("type", "");

        if (msgType == "handshake_response") {
            bool success = msg.value("success", false);
            if (success) {
                serverUdpHost = msg.value("udpHost", "");
                serverUdpPort = msg.value("udpPort", 0);
                serverSessionKey = msg.value("sessionKey", "");
                handshakeSuccess = true;
            }
            handshakeCompleted = true;
            handshakeCondition.notify_one();
        }
        // Handle other control messages as needed
    } catch (const std::exception& e) {
        LOG_ERROR("Error handling control message: %s", e.what());
    }
}

void MqttProtocol::receiveAudioPackets(const std::string& sessionKey) {
    std::vector<uint8_t> buffer(MAX_PACKET_SIZE);
    uint32_t expectedSequence = 0;

    while (isAudioChannelOpen) {
        try {
            int bytesRead = udpSocket->receive(buffer.data(), buffer.size());
            if (bytesRead <= 0) {
                continue;
            }

            // Decrypt packet
            std::vector<uint8_t> decryptedData;
            if (!decryptPacket(buffer.data(), bytesRead, sessionKey, decryptedData)) {
                LOG_WARN("Failed to decrypt audio packet");
                continue;
            }

            // Parse packet header for sequence number
            if (decryptedData.size() < sizeof(PacketHeader)) {
                LOG_WARN("Invalid packet size");
                continue;
            }

            PacketHeader* header = reinterpret_cast<PacketHeader*>(decryptedData.data());
            uint32_t sequenceNumber = ntohl(header->sequenceNumber);

            // Check packet sequence
            if (sequenceNumber != expectedSequence) {
                LOG_WARN("Packet sequence mismatch: expected %u, got %u", expectedSequence, sequenceNumber);
                // Handle sequence gap or duplicate
                if (sequenceNumber < expectedSequence) {
                    continue; // Duplicate packet
                }
                // Missing packets - could implement interpolation or error concealment
            }

            expectedSequence = sequenceNumber + 1;

            // Extract OPUS audio data (skip header)
            std::vector<uint8_t> opusData(decryptedData.begin() + sizeof(PacketHeader), 
                                        decryptedData.end());

            // Pass to callback
            if (audioCallback) {
                AudioPacket packet;
                packet.sequenceNumber = sequenceNumber;
                packet.timestamp = ntohl(header->timestamp);
                packet.data = std::move(opusData);
                packet.receiveTime = std::chrono::steady_clock::now();

                audioCallback(packet);
            }

            lastPacketTime = std::chrono::steady_clock::now();

        } catch (const std::exception& e) {
            LOG_ERROR("Error receiving audio packet: %s", e.what());
            if (isAudioChannelOpen) {
                // Check for timeout
                auto now = std::chrono::steady_clock::now();
                auto duration = std::chrono::duration_cast<std::chrono::seconds>(
                    now - lastPacketTime);
                if (duration.count() > PACKET_TIMEOUT) {
                    LOG_ERROR("Audio packet timeout - closing channel");
                    closeAudioChannel();
                }
            }
        }
    }
}

bool MqttProtocol::decryptPacket(const uint8_t* encryptedData, size_t dataSize, 
                                const std::string& key, std::vector<uint8_t>& decryptedData) {
    try {
        // Initialize decryption with session key
        CryptoAES aes(key);
        return aes.decrypt(encryptedData, dataSize, decryptedData);
    } catch (const std::exception& e) {
        LOG_ERROR("Decryption failed: %s", e.what());
        return false;
    }
}

void MqttProtocol::cleanupAudioChannel() {
    isAudioChannelOpen = false;

    if (audioReceptionThread.joinable()) {
        audioReceptionThread.join();
    }

    if (udpSocket) {
        udpSocket->close();
        udpSocket.reset();
    }
}

